(function(w){w.__PC_DUOC_CHUNKS=w.__PC_DUOC_CHUNKS||{};w.__PC_DUOC_CHUNKS["jci-04"]=[{"c":"FMS.07.01","ch":"FMS","t":"Bệnh viện có quy trình giám sát và xử lý các thông báo nguy hiểm về thiết bị y tế, thu hồi, sự cố cần báo cáo, vấn đề và lỗi.","p":"Sự cố thiết bị y tế gây ra rủi ro cho bệnh nhân, nhà cung cấp và các nhân viên khác, và việc có các quy trình tại\nchỗ đảm bảo nhận thức được các vấn đề và cho phép hành động để ngăn ngừa tác hại.\n\nBệnh viện có một hệ thống để giám sát và hành động theo các thông báo nguy hiểm về thiết bị y tế, lệnh thu\nhồi, sự cố có thể báo cáo, vấn đề và lỗi do nhà sản xuất, nhà cung cấp hoặc cơ quan quản lý gửi. Một số quốc\ngia yêu cầu báo cáo bất kỳ thiết bị y tế nào liên quan đến tử vong, thương tích nghiêm trọng hoặc bệnh tật.\nBệnh viện phải xác định và tuân thủ các luật và quy định liên quan đến việc báo cáo các sự cố về thiết bị y tế.\nBệnh viện tiến hành phân tích nguyên nhân gốc rễ để ứng phó với bất kỳ sự kiện cảnh báo nào.\n\nCác yếu tố đo lường được của FMS.07.01\n1.\nBệnh viện có quy trình giám sát và hành động đối với các thông báo về nguy cơ, thu hồi, sự cố, vấn đề và\nlỗi liên quan đến thiết bị y tế và thiết bị cấy ghép. (Xem thêm AOP.03.04, ME 5; AOP.05.04, ME 5)\n2.\nBệnh viện báo cáo bất kỳ trường hợp tử vong, thương tích nghiêm trọng hoặc bệnh tật nào là hậu quả\ncủa thiết bị y tế thông qua quy trình báo cáo sự cố và biến cố bất lợi của bệnh viện. (Xem thêm\nGLD.04.00, ME 7)\n3.\nChương trình quản lý thiết bị y tế giải quyết việc sử dụng bất kỳ thiết bị y tế nào có sự cố hoặc lỗi được\nbáo cáo, hoặc là đối tượng của thông báo nguy hiểm hoặc đang bị thu hồi.\n\nHệ thống tiện ích","m":[]},{"c":"FMS.08.00","ch":"FMS","t":"Bệnh viện triển khai chương trình quản lý hệ thống tiện ích trong toàn bộ tổ chức.","p":"Tiện ích có thể được định nghĩa là các hệ thống và thiết bị hỗ trợ các dịch vụ thiết yếu cung cấp dịch vụ chăm sóc sức\nkhỏe an toàn. Các hệ thống đó bao gồm phân phối điện; điện; hệ thống ống nước; lò hơi/hơi nước; hệ thống sưởi ấm,\nthông gió và điều hòa không khí (HVAC); khí y tế; máy hút bụi y tế/phẫu thuật; quản lý chất thải; và hệ thống truyền\nthông\nvà dữ liệu. Việc vận hành an toàn, hiệu quả và hiệu suất của tiện ích và các hệ thống quan trọng khác trong bệnh viện là\ncần thiết để đảm bảo an toàn cho bệnh nhân, nhân viên và khách đến thăm cũng như đáp ứng nhu cầu chăm sóc bệnh\nnhân. Chăm sóc bệnh nhân, cả thường quy và khẩn cấp, được cung cấp 24 giờ, tất cả các ngày trong tuần tại bệnh viện.\nDo đó, nguồn tiện ích thiết yếu không bị gián đoạn là rất quan trọng để đáp ứng nhu cầu chăm sóc bệnh nhân.\n\nBệnh viện xây dựng và triển khai một chương trình bằng văn bản để quản lý các hệ thống tiện ích trong toàn bệnh viện.\nChương trình hệ thống tiện ích bao gồm kiểm tra, thử nghiệm và bảo trì để đảm bảo rằng các tiện ích hoạt động hiệu quả\nvà hiệu suất cao để đáp ứng nhu cầu của bệnh nhân, nhân viên và khách đến thăm.\n\nMột chương trình quản lý tiện ích tốt sẽ đảm bảo độ tin cậy của các hệ thống tiện ích và giảm thiểu các rủi ro tiềm ẩn. Ví\ndụ, ô nhiễm nước, thông gió không hiệu quả trong các khu vực chăm sóc đặc biệt, bình oxy không được cố định khi lưu\ntrữ, đường ống oxy bị rò rỉ và đường dây điện bị sờn đều gây ra mối nguy hiểm. Để tránh những rủi ro này và các rủi ro\nkhác, bệnh viện có quy trình kiểm tra thường xuyên các hệ thống như vậy và thực hiện bảo trì phòng ngừa và bảo trì\nthường xuyên. Trong quá trình thử nghiệm, cần chú ý đến các thành phần quan trọng (ví dụ: công tắc và rơle) của hệ\nthống.\n\nBệnh viện nên có danh mục đầy đủ tất cả các thành phần của hệ thống tiện ích và xác định thành phần nào có tác động lớn\nnhất đến hỗ trợ sự sống, phòng ngừa và kiểm soát nhiễm trùng, hỗ trợ môi trường và giao tiếp. Chương trình quản lý tiện\ních bao gồm các chiến lược bảo trì tiện ích đảm bảo\ncác thành phần chính của hệ thống này, chẳng hạn như điện, nước, chất thải, thông gió và khí y tế, được kiểm tra, đánh\ngiá, bảo trì thường xuyên và khi cần thiết, được cải thiện để giảm thiểu và loại bỏ rủi ro.\n\nCác yếu tố đo lường được của FMS.08.00\n1.\nBệnh viện xây dựng và triển khai chương trình bằng văn bản để quản lý hệ thống tiện ích trong toàn\nbệnh viện. (Xem thêm HCT.01.04, ME 1)\n2.\nBệnh viện xác định mục tiêu, triển khai cải tiến và theo dõi dữ liệu để đảm bảo rủi ro của hệ thống tiện\ních được giảm thiểu hoặc loại bỏ.\n3.\nBệnh viện lập danh mục các thành phần hệ thống tiện ích và lập bản đồ phân phối hiện tại của chúng.\n4.\nBệnh viện xác định, bằng văn bản, các hoạt động và khoảng thời gian để kiểm tra, đánh giá và tiến hành\nbảo trì phòng ngừa và bảo trì thường xuyên đối với tất cả các thành phần hoạt động của hệ thống tiện\ních trong danh mục, dựa trên các tiêu chí như khuyến nghị của nhà sản xuất, mức độ rủi ro và kinh\nnghiệm của bệnh viện.\n5.\nBệnh viện dán nhãn các biện pháp kiểm soát hệ thống tiện ích để tạo điều kiện cho việc tắt máy khẩn\ncấp một phần hoặc toàn bộ.","m":[],"sec":"Hệ thống tiện ích"},{"c":"FMS.08.01","ch":"FMS","t":"Chương trình hệ thống tiện ích bệnh viện đảm bảo các tiện ích thiết yếu, bao gồm điện, nước và khí y tế, luôn sẵn sàng và các nguồn thay thế cho các tiện ích thiết yếu được thử nghiệm và đánh giá. 183 Facility Management and Safety (FMS) Ủy ban chung Quốc tế aCCreditation standards for Hospitals, 8tH edition.","p":"Chăm sóc bệnh nhân, cả thường quy và khẩn cấp, được cung cấp 24 giờ, tất cả các ngày trong tuần tại bệnh viện. Các\nbệnh viện có nhu cầu về hệ thống tiện ích khác nhau dựa trên nhiệm vụ, nhu cầu của bệnh nhân và nguồn lực của họ.\nTuy nhiên, nguồn tiện ích thiết yếu không bị gián đoạn, bao gồm nước, điện và khí y tế, là rất quan trọng để đáp ứng\nnhu cầu chăm sóc bệnh nhân.\n\nHệ thống điện khẩn cấp là bắt buộc đối với tất cả các bệnh viện có ý định cung cấp dịch vụ liên tục trong điều kiện\nkhẩn cấp. Hệ thống như vậy cung cấp đủ điện để duy trì các chức năng thiết yếu trong thời gian mất điện. Nó cũng\nlàm giảm rủi ro liên quan đến các sự cố như vậy. Các nguồn điện khẩn cấp và dự phòng được thử nghiệm trong các\ntrường hợp đã lên kế hoạch mô phỏng các yêu cầu tải thực tế. Ví dụ, đối với thử nghiệm hàng quý, yêu cầu là thử\nnghiệm phải chạy trong 30 phút và phải đạt 30% tải định mức.\nKhung thời gian 30 phút không bao gồm thời gian khởi động hoặc làm mát. Các bệnh viện có thể chọn các phương\npháp thử nghiệm khác đáp ứng các tiêu chuẩn của ngành.\n\nChất lượng nước có thể thay đổi đột ngột do nhiều nguyên nhân, một số nguyên nhân xảy ra bên ngoài bệnh viện,\nchẳng hạn như đường ống cung cấp cho bệnh viện bị đứt. Khi nguồn nước thông thường cung cấp cho tổ chức bị\ngián đoạn, nguồn cung cấp nước uống khẩn cấp phải có sẵn ngay lập tức.\n\nBất kể loại hệ thống và mức độ nguồn lực nào, bệnh viện cần bảo vệ bệnh nhân và nhân viên trong các trường hợp\nkhẩn cấp, chẳng hạn như khi các tiện ích thiết yếu bị hỏng, bị gián đoạn hoặc bị ô nhiễm. Để chuẩn bị cho các trường\nhợp khẩn cấp như vậy, bệnh viện thực hiện các bước sau:\n• Xác định các tiện ích thiết yếu dựa trên các hệ thống, thiết bị và địa điểm gây ra rủi ro cao nhất cho bệnh nhân và\nnhân viên nếu các tiện ích bị gián đoạn, hỏng hoặc không khả dụng (ví dụ: các hệ thống, thiết bị và địa điểm chính cần\nchiếu sáng, làm lạnh, hỗ trợ sự sống, nước để vệ sinh và khử trùng vật tư).\n• Đánh giá và giảm thiểu rủi ro hệ thống tiện ích bị hỏng ở những khu vực này.\n• Lên kế hoạch cung cấp điện khẩn cấp và nguồn nước sạch cho các khu vực và nhu cầu này.\n• Kiểm tra tính khả dụng và độ tin cậy của các nguồn điện và nước khẩn cấp.\n• Ghi lại kết quả kiểm tra.\n• Đảm bảo rằng việc thử nghiệm và đánh giá các nguồn nước thay thế diễn ra ít nhất hàng năm hoặc thường xuyên\nhơn nếu được yêu cầu bởi luật pháp, quy định hoặc điều kiện của địa phương về nguồn nước (ví dụ về\nđiều kiện của nguồn nước có thể làm tăng tần suất thử nghiệm bao gồm việc sửa chữa hệ thống nước nhiều lần và\nnguồn nước bị ô nhiễm thường xuyên). • Đảm bảo rằng việc thử nghiệm và đánh giá điện diễn ra ít nhất hàng quý\nhoặc thường xuyên hơn nếu được yêu cầu bởi luật pháp, quy định, khuyến nghị của nhà sản xuất hoặc điều kiện của\nnguồn điện (ví dụ về điều kiện của nguồn điện có thể làm tăng tần suất thử nghiệm bao gồm lưới điện không đáng tin\ncậy và tình trạng mất điện liên tục, không thể đoán trước).\n\nKhi hệ thống điện khẩn cấp yêu cầu nguồn nhiên liệu, việc xác định lượng nhiên liệu cần lưu trữ tại chỗ phải bao\ngồm việc xem xét các lần mất điện trước đây và bất kỳ vấn đề giao hàng dự kiến nào do tình trạng thiếu hụt, thời tiết\nvà điều kiện địa lý và vị trí. Bệnh viện có thể xác định lượng nhiên liệu được lưu trữ trừ khi luật pháp và quy\nđịnh/chính quyền địa phương chỉ định lượng.\n\nCác yếu tố đo lường được của FMS.08.01\n1.\nBệnh viện đảm bảo tính khả dụng/tính liên tục của các tiện ích thiết yếu (bao gồm điện, nước và khí y\ntế) 24 giờ một ngày, 7 ngày một tuần. (Xem thêm FMS.09.00, ME 1)\n2.\nBệnh viện kiểm tra và đánh giá tính khả dụng và chất lượng của các nguồn nước thay thế ít nhất hàng\nnăm hoặc thường xuyên hơn nếu luật pháp và quy định của địa phương hoặc điều kiện của nguồn nước\nyêu cầu. Bệnh viện ghi lại kết quả của các cuộc kiểm tra.\n3.\nBệnh viện kiểm tra và đánh giá các nguồn điện thay thế ít nhất hàng quý hoặc thường xuyên hơn\nnếutheo luật pháp và quy định của địa phương, khuyến nghị của nhà sản xuất hoặc điều kiện của nguồn\nđiện yêu cầu. Bệnh viện ghi lại kết quả của các cuộc kiểm tra.","m":[]},{"c":"FMS.08.02","ch":"FMS","t":"Cá nhân hoặc cơ quan được chỉ định giám sát chất lượng nước thường xuyên.","p":"Chất lượng nước dễ thay đổi đột ngột, bao gồm cả những thay đổi nằm ngoài tầm kiểm soát của bệnh viện.\nBệnh viện phải duy trì chất lượng nước vì đây là yếu tố quan trọng trong các quy trình chăm sóc lâm sàng, bao\ngồm các thủ thuật nha khoa và chạy thận nhân tạo. Do đó, bệnh viện thiết lập quy trình theo dõi và duy trì chất\nlượng nước, đồng thời thực hiện các hành động khi phát hiện chất lượng nước không an toàn.\n\nSố lượng địa điểm xét nghiệm chất lượng nước do bệnh viện xác định dựa trên đánh giá rủi ro của riêng bệnh\nviện. Việc xét nghiệm nước uống và/hoặc nước không uống được được tiến hành thường xuyên. Tần suất xét\nnghiệm có thể dựa trên bất kỳ hoặc tất cả các yếu tố sau:\n• Luật pháp và quy định của địa phương\n• Điều kiện của nguồn nước\n• Kinh nghiệm trước đây về các vấn đề về chất lượng nước\n\nXét nghiệm có thể được thực hiện bởi những cá nhân do bệnh viện chỉ định, chẳng hạn như nhân viên phòng xét\nnghiệm lâm sàng, hoặc bởi các cơ quan y tế công cộng hoặc kiểm soát nước bên ngoài bệnh viện, hoặc những\nngười khác được đánh giá là có đủ năng lực để thực hiện các xét nghiệm đó. Cho dù được thực hiện bởi nhân\nviên bệnh viện có trình độ hay bởi các cơ quan bên ngoài bệnh viện, hoặc những cá nhân có trình độ khác, thì\nbệnh viện có trách nhiệm đảm bảo rằng xét nghiệm được hoàn tất và ghi chép lại.\n\nNgoài việc kiểm tra chất lượng nước, để ngăn ngừa và giảm nguy cơ ô nhiễm và phát triển của vi khuẩn như\nEscherichia coli, Legionella và nhiều loại khác, cần tham khảo hướng dẫn từ chương trình phòng ngừa và kiểm\nsoát nhiễm trùng của bệnh viện cũng như dữ liệu từ các sự cố bất lợi liên quan đến chất lượng nước của bệnh\nnhân. Những nguồn này giúp thông báo liệu có nên thực hiện các hành động, chẳng hạn như các biện pháp\nphòng ngừa, để giảm nguy cơ ô nhiễm và phát triển của vi khuẩn hay không.\n\nNước là một phần không thể thiếu của dịch vụ chăm sóc răng miệng. Các bệnh viện cung cấp dịch vụ nha khoa\nthực hiện các biện pháp để đảm bảo rằng nước được sử dụng trong các quy trình và phương pháp điều trị nha\nkhoa là an toàn. Điều này bao gồm việc tuân thủ các hướng dẫn của nhà sản xuất để xử lý và kiểm tra đường ống\nnước của đơn vị nha khoa. Bệnh viện đảm bảo rằng đội ngũ nhân viên nha khoa được đào tạo và hiểu các yêu cầu\nvà quy trình xử lý và kiểm tra đường ống nước của đơn vị nha khoa.\n\nCác yếu tố đo lường được của FMS.08.02\n1. Chất lượng nước uống được kiểm tra và đánh giá ít nhất một quý hoặc thường xuyên hơn theo luật\npháp và quy định, điều kiện của nguồn nước và kinh nghiệm trước đây về các vấn đề chất lượng\nnước. Kết quả kiểm tra được ghi lại.\n2. Chất lượng nước không uống được được kiểm tra và đánh giá ít nhất sáu (6) tháng một lần hoặc\nthường xuyên hơn dựa trên luật pháp và quy định của địa phương, điều kiện của nguồn nước và kinh\nnghiệm trước đây về các vấn đề chất lượng nước. Kết quả kiểm tra được ghi lại.\n3. Các biện pháp và chiến lược phòng ngừa được thực hiện để giảm nguy cơ ô nhiễm và phát triển của vi\nkhuẩn trong nước.\n4. Đường ống nước của đơn vị nha khoa được xử lý, kiểm tra và đánh giá theo hướng dẫn của nhà sản\nxuất, và các phương pháp xử lý và kiểm tra được ghi lại.","m":[],"sec":"Hệ thống tiện ích"},{"c":"FMS.08.03","ch":"FMS","t":"Chất lượng nước sử dụng trong quá trình thẩm phân máu được kiểm tra và đánh giá về các chất gây ô nhiễm hóa học, vi khuẩn và nội độc tố, và các quy trình cho dịch vụ thẩm phân máu tuân theo các tiêu chuẩn chuyên nghiệp về chất lượng nước và phòng ngừa và kiểm soát nhiễm trùng. 185 Facility Management and Safety (FMS) Ủy ban chung Quốc tế aCCreditation standards for Hospitals, 8tH edition.","p":"Chất lượng nước là yếu tố cần thiết để thực hiện chạy thận nhân tạo an toàn và hiệu quả, vì những bệnh\nnhân này có thể dễ bị nhiễm trùng và có kết quả bất lợi hơn.\n\nCác quy trình và thủ thuật được sử dụng trong chạy thận nhân tạo phải tuân thủ nghiêm ngặt các tiêu chuẩn\ncủa ngành và hướng dẫn chuyên môn về chất lượng nước và các biện pháp phòng ngừa và kiểm soát nhiễm\ntrùng, chẳng hạn như Hiệp hội Phát triển Thiết bị Y tế (AAMI). Điều này bao gồm nhưng không giới hạn ở\nviệc kiểm tra nước\nđược sử dụng để chạy thận nhân tạo trước và trong quá trình chạy thận nhân tạo theo các hướng dẫn dựa\ntrên bằng chứng và các cơ quan có thẩm quyền khác, tối thiểu hàng tháng để phát hiện sự phát triển của vi\nkhuẩn và độc tố nội sinh, và kiểm tra tối thiểu hàng năm để phát hiện hóa chất và các chất gây ô nhiễm khác\nnhư asen và kim loại nặng. Việc lấy mẫu nước\nđể kiểm tra từ cả máy chạy thận nhân tạo/bộ xử lý thẩm thấu ngược/bộ lọc trước và sau khi chạy thận nhân\ntạo cũng rất quan trọng khi được yêu cầu theo các tiêu chuẩn của ngành và hướng dẫn chuyên môn, để đảm\nbảo nguồn nước đầu vào không bị ô nhiễm và đáp ứng các tiêu chuẩn về chất lượng nước, đồng thời đảm\nbảo các máy móc và bộ phận thẩm thấu ngược hoạt động như mong đợi.\n\nCác hành động khác để đảm bảo chất lượng nước phù hợp và giảm nguy cơ nhiễm trùng trong các dịch vụ\nchạy thận nhân tạo bao gồm khử trùng thường xuyên hệ thống phân phối nước và thử nghiệm máy chạy thận\nnhân tạo. Tần suất khử trùng hệ thống phân phối nước phụ thuộc vào các yếu tố như thiết kế của hệ thống\nvà mức độ\nphòng ngừa cần thiết để kiểm soát màng sinh học vi khuẩn hình thành bên trong đường ống nước.\n\nXử lý chất lượng nước và kết quả thử nghiệm được ghi lại.\n\nKhi áp dụng cho các dịch vụ của mình, bệnh viện thiết lập và triển khai các quy trình xử lý lại máy lọc máu,\nchẳng hạn như quy trình vệ sinh, thử nghiệm và lưu trữ máy lọc máu và tần suất tái sử dụng/thay thế chúng.\n\nKhi gặp phải vấn đề về chất lượng nước trong bệnh viện, các hành động được thực hiện để giải quyết các\nvấn đề trong khi vẫn đảm bảo an toàn cho bệnh nhân trong tổ chức. Ví dụ, các vấn đề về chất lượng nước có\nthể yêu cầu bệnh viện phải hạn chế một số dịch vụ nhất định hoặc sử dụng các nguồn nước thay thế cho đến\nkhi vấn đề được giải quyết. Sau khi vấn đề được giải quyết và việc theo dõi chất lượng nước chứng minh\nrằng nước an toàn, bệnh viện sẽ quay trở lại các dịch vụ chăm sóc bệnh nhân thông thường.\n\nCác yếu tố đo lường được của FMS.08.03\n1.\nDịch vụ thẩm phân máu tại bệnh viện tuân thủ các tiêu chuẩn của ngành và hướng dẫn chuyên môn để duy\ntrì chất lượng nước và thực hiện các biện pháp phòng ngừa và kiểm soát nhiễm trùng.\n2.\nNước sử dụng trong thẩm phân máu được thử nghiệm theo các hướng dẫn dựa trên bằng chứng trước và\ntrong quá trình điều trị và được đánh giá hàng tháng về sự phát triển của vi khuẩn và độc tố nội sinh và\nđược đánh giá hàng năm về các chất gây ô nhiễm hóa học. Kết quả thử nghiệm được ghi lại.\n3.\nBệnh viện thực hiện khử trùng thường quy hệ thống phân phối nước thẩm phân máu.\n4.\nBệnh viện tiến hành thử nghiệm và đánh giá tất cả các máy thẩm phân máu hàng năm, bao gồm các máy\nkhông sử dụng và kết quả thử nghiệm được ghi lại.\n5.\nBệnh viện thiết lập và triển khai các quy trình để xử lý lại máy thẩm phân, bao gồm, nếu có, tần suất tái sử\ndụng/thay thế máy thẩm phân và các quy trình vệ sinh và thử nghiệm máy thẩm phân.","m":[]},{"c":"FMS.08.04","ch":"FMS","t":"Bệnh viện giảm nguy cơ lây nhiễm trong cơ sở thông qua việc sử dụng các biện pháp kiểm soát cơ học và kỹ thuật.","p":"Các biện pháp kiểm soát kỹ thuật, chẳng hạn như hệ thống thông gió áp suất dương và áp suất âm, tủ hút\nsinh học trong phòng thí nghiệm và bộ điều chỉnh nhiệt độ trên các thiết bị làm lạnh và trên máy nước\nnóng dùng để khử trùng bát đĩa và thiết bị nhà bếp, là những ví dụ về cách các tiêu chuẩn và biện pháp\nkiểm soát môi trường góp phần vào vệ sinh tốt và giảm nguy cơ nhiễm trùng trong bệnh viện.\n\nHệ thống thông gió áp suất dương được sử dụng trong các khu vực bảo vệ của bệnh viện đòi hỏi mức độ sạch sẽ cao nhất;\nví dụ, phòng phẫu thuật, khu vực lưu trữ vô trùng và phòng dành cho bệnh nhân suy giảm miễn dịch. Thông gió áp suất\ndương đảm bảo không khí được dẫn ra khỏi khu vực, giảm thiểu khả năng vi sinh vật xâm nhập vào môi trường.\n\nBệnh viện xác định và tuân thủ luật pháp, quy định của địa phương và quốc gia cũng như các tiêu chuẩn chuyên môn liên\nquan đến việc sử dụng và bảo trì hệ thống thông gió áp suất dương.\n\nNhiệt độ nước và hơi nước thích hợp là cần thiết để ngăn ngừa sự phát triển của vi sinh vật và thực hiện thành công các\nquy trình vệ sinh, khử trùng và tiệt trùng. Lãnh đạo bệnh viện tham khảo luật pháp, quy định của địa phương và quốc gia\ncũng như các hướng dẫn chuyên môn để xác định nhiệt độ nước và hơi nước thích hợp\nđể giảm thiểu khả năng lây truyền nhiễm trùng qua nước. Ngoài ra, lãnh đạo bệnh viện đảm bảo rằng nước và hơi nước\nđạt đến nhiệt độ cần thiết trong thời gian thích hợp để thực hiện hiệu quả bất kỳ quy trình vệ sinh, khử trùng hoặc tiệt\ntrùng nào; ví dụ, nhiệt độ nước thích hợp để rửa chén và nhiệt độ hơi nước để hấp tiệt trùng.\n\nBệnh viện vận hành và bảo trì luồng không khí, hệ thống thông gió và kiểm soát độ ẩm để duy trì chất lượng không khí\ntrong nhà. Điều này bao gồm việc bảo trì hệ thống sưởi ấm, thông gió và điều hòa không khí (HVAC) theo cách giảm thiểu\nrủi ro lây nhiễm cho bệnh nhân, nhân viên và khách. Các chất gây ô nhiễm trong không khí có thể lây lan qua khí thải, thông\nqua hệ thống thông gió chung và trong quá trình vệ sinh. Việc bảo trì hệ thống luồng không khí và thông gió có thể giảm\nthiểu rủi ro này. Hoạt động và bảo trì được hoàn thành theo luật pháp và quy định của địa phương và quốc gia cũng như\ncác hướng dẫn chuyên môn và bao gồm việc bảo trì đúng cách các cửa hút, cửa thoát, quạt, bộ lọc, bộ khuếch tán, ống dẫn,\nmáy tạo độ ẩm, v.v.\n\nCác yếu tố đo lường được của FMS.08.04\n1.\nBệnh viện vận hành và bảo trì các hệ thống thông gió áp suất âm và áp suất dương theo luật pháp và quy\nđịnh của địa phương và quốc gia cũng như các tiêu chuẩn chuyên môn.\n2.\nBệnh viện vận hành và bảo trì các biện pháp kiểm soát nhiệt độ cho nước, hơi nước và các biện pháp\nkhác theo luật pháp và quy định của địa phương và quốc gia cũng như các tiêu chuẩn chuyên môn.\n3.\nBệnh viện vận hành và bảo trì luồng không khí, hệ thống thông gió và kiểm soát độ ẩm theo cách giảm\nthiểu nguy cơ nhiễm trùng trong bệnh viện theo luật pháp và quy định của địa phương và quốc gia cũng\nnhư các hướng dẫn chuyên môn.\n\nQuản lý khẩn cấp và thiên tai","m":[]},{"c":"FMS.09.00","ch":"FMS","t":"Bệnh viện xây dựng, duy trì và đánh giá chương trình quản lý tình trạng khẩn cấp để ứng phó với các trường hợp khẩn cấp và thảm họa bên trong và bên ngoài có khả năng xảy ra trong bệnh viện và cộng đồng.","p":"Các trường hợp khẩn cấp và thảm họa trong cộng đồng có thể liên quan trực tiếp đến bệnh viện, chẳng\nhạn như thiệt hại cho khu vực chăm sóc bệnh nhân\ndo động đất, sóng thần hoặc tấn công khủng bố khiến nhân viên không thể đến làm việc. Để lập kế\nhoạch, chuẩn bị\nvà ứng phó hiệu quả với các trường hợp khẩn cấp và thảm họa, bệnh viện xây dựng và triển khai\nchương trình quản lý thảm họa và\nkhẩn cấp.\n\nViệc xây dựng chương trình bắt đầu bằng cách xác định các loại trường hợp khẩn cấp và thảm họa có\nkhả năng xảy ra trong khu vực của bệnh viện (ví dụ: động đất, bão, lũ lụt, lở đất, nổ) và tác động của\ncác trường hợp khẩn cấp và thảm họa này đối với bệnh viện. Ví dụ, bão hoặc sóng thần có nhiều khả\nnăng xảy ra ở những khu vực gần biển; tuy nhiên, thiệt hại về cơ sở vật chất hoặc thương vong hàng\nloạt do chiến tranh hoặc tấn công khủng bố có khả năng xảy ra ở bất kỳ bệnh viện nào.\n\nChương trình phải giải quyết tất cả sáu yếu tố quan trọng:\n• Giao tiếp\n• Nguồn lực và tài sản\n• An toàn và bảo mật\n• Trách nhiệm của nhân viên\n• Quản lý tiện ích\n• Các hoạt động hỗ trợ và lâm sàng cho bệnh nhân\n\nBệnh viện đóng vai trò quan trọng trong cộng đồng trong các trường hợp khẩn cấp và thảm họa.\nĐể bệnh viện có thể duy trì hoạt động trong và sau các trường hợp khẩn cấp và thảm họa, điều\nquan trọng là phải đánh giá và xác định các hạn chế về mặt cấu trúc và phi cấu trúc của các tòa nhà\nbệnh viện. Xác định cách các tòa nhà sẽ ứng phó với các trường hợp khẩn cấp và thảm họa có khả\nnăng xảy ra trong khu vực là một khía cạnh quan trọng trong việc xây dựng các kế hoạch sơ tán và\nxác định các khu vực ưu tiên để cải thiện tòa nhà.\n\nĐánh giá các yếu tố cấu trúc bao gồm loại thiết kế và vật liệu xây dựng cũng như các thành phần\ncủa hệ thống chịu tải của tòa nhà, bao gồm móng, cột, dầm, tường, sàn, v.v. Vị trí của tòa nhà\ncũng được coi là một phần của các yếu tố cấu trúc (ví dụ, rủi ro liên quan đến vị trí gần các tòa nhà\nkhác, vị trí trong vùng nguy hiểm như vùng đồng bằng ngập lụt và các vấn đề khác). Đánh giá các\nyếu tố phi cấu trúc bao gồm các yếu tố kiến trúc không chịu lực (như mái, trần nhà, cửa sổ và cửa\nra vào); lối ra vào khẩn cấp đến và đi từ bệnh viện; các hệ thống quan trọng (như điện, hệ thống\nống nước, quản lý chất thải và phòng cháy chữa cháy); thiết bị y tế và phòng xét nghiệm; và các\nyếu tố phi cấu trúc khác có vai trò thiết yếu đối với hoạt động an toàn của bệnh viện. Đánh giá các\nyếu tố cấu trúc và phi cấu trúc cho phép bệnh viện xác định các điểm yếu và lập kế hoạch giải\nquyết các điểm yếu này cũng như cải thiện sự an toàn và khả năng chuẩn bị của bệnh viện.\n\nViệc xác định các tác động có thể xảy ra của trường hợp khẩn cấp hoặc thảm họa cũng quan trọng\nnhư việc xác định các loại trường hợp khẩn cấp và thảm họa có khả năng xảy ra. Điều này giúp\nlập kế hoạch các chiến lược cần thiết trong trường hợp bệnh viện gặp phải trường hợp khẩn cấp\nhoặc thảm họa. Ví dụ, khả năng một thảm họa thiên nhiên, chẳng hạn như động đất, sẽ ảnh\nhưởng đến nước và điện là bao nhiêu? Động đất có thể ngăn cản nhân viên ứng phó với\nthảm họa, vì đường sá bị chặn hoặc vì họ hoặc các thành viên gia đình họ cũng là nạn nhân của sự\nkiện này không? Trong những tình huống như vậy, trách nhiệm của nhân viên đối với gia đình\nvà/hoặc sự an toàn cá nhân có thể khiến họ khó hoặc không thể có mặt tại bệnh viện để ứng phó\nvới trường hợp khẩn cấp hoặc thảm họa. Bệnh viện cần xác định và lập kế hoạch cho các nguồn\nlực khác khi nhân viên không thể đến bệnh viện để cung cấp và hỗ trợ chăm sóc bệnh nhân trong\ntrường hợp khẩn cấp hoặc thảm họa.\n\nNgoài ra, bệnh viện cần xác định vai trò của họ trong cộng đồng. Ví dụ, bệnh viện sẽ phải cung\ncấp những nguồn lực nào cho cộng đồng trong trường hợp xảy ra trường hợp khẩn cấp hoặc\nthảm họa và sẽ sử dụng những phương pháp truyền thông nào trong cộng đồng?\n\nChương trình quản lý trường hợp khẩn cấp và thảm họa được đánh giá bằng một cuộc kiểm tra\nhàng năm đối với toàn bộ chương trình trong nội bộ hoặc như một phần của cuộc kiểm tra toàn\ncộng đồng hoặc kiểm tra các yếu tố quan trọng của chương trình trong năm.\n\nNếu bệnh viện gặp phải trường hợp khẩn cấp hoặc thảm họa thực sự, kích hoạt chương trình của\nmình và tóm tắt lại sau đó, tình huống này tương đương với một cuộc kiểm tra hàng năm.\n\nCác yếu tố đo lường được của FMS.09.00\n1.\nBệnh viện xây dựng, đánh giá và duy trì chương trình quản lý thảm họa và tình trạng khẩn cấp bằng văn bản cung\ncấp các quy trình cho các mục đích sau:\n•\nXác định loại, khả năng xảy ra và hậu quả của các mối nguy hiểm, mối đe dọa và sự kiện (Xem thêm\n•\nGHI.05.00, ME 2)\n•\nXác định các lỗ hổng về mặt cấu trúc và phi cấu trúc của môi trường chăm sóc bệnh nhân của bệnh viện và cách\nbệnh viện sẽ hoạt động trong trường hợp khẩn cấp hoặc thảm họa\n•\nLên kế hoạch cho các nguồn điện và nước thay thế trong trường hợp khẩn cấp và thảm họa\n•\nXác định vai trò của bệnh viện trong các sự kiện như vậy\n•\nXác định các chiến lược truyền thông cho các sự kiện\n•\nQuản lý các nguồn lực trong các sự kiện, bao gồm các nguồn thay thế (Xem thêm FMS.08.01, ME 1)\n•\nQuản lý các hoạt động lâm sàng trong một sự kiện, bao gồm các địa điểm chăm sóc thay thế\n•\nXác định và phân công vai trò và trách nhiệm của nhân viên trong một sự kiện (bao gồm nhân viên hợp đồng,\nnhà cung cấp và những người khác do bệnh viện xác định) (Xem thêm GHI.05.00, ME 4)\n•\nQuản lý các trường hợp khẩn cấp và thảm họa khi trách nhiệm cá nhân của nhân viên xung đột với trách nhiệm\ncủa bệnh viện trong việc cung cấp dịch vụ chăm sóc bệnh nhân\n2.\nBệnh viện xác định các trường hợp khẩn cấp và/hoặc thảm họa lớn bên trong và bên ngoài như trường hợp khẩn cấp\ncủa cộng đồng, và các thảm họa thiên nhiên hoặc các thảm họa khác gây ra rủi ro đáng kể khi xảy ra, có tính đến vị trí\nđịa lý của bệnh viện. (Xem thêm GHI.05.00, ME 2)\n3.\nBệnh viện xác định và tiến hành đánh giá hàng năm các yếu tố quan trọng của chương trình quản lý thảm họa và\nkhẩn cấp. Tối thiểu, các yếu tố quan trọng bao gồm những điều sau:\n•\nLoại, khả năng xảy ra và hậu quả của các mối nguy hiểm, mối đe dọa và sự kiện\n•\nCác lỗ hổng về mặt cấu trúc và phi cấu trúc của môi trường chăm sóc bệnh nhân của bệnh viện và cách bệnh\nviện sẽ hoạt động trong trường hợp khẩn cấp hoặc thảm họa (Xem thêm GHI.05.00, ME 3)\n•\nCác nguồn điện và nước thay thế trong trường hợp khẩn cấp và thảm họa\n4. Các hành động tiếp theo được xác định từ thử nghiệm và tóm tắt được phát triển và triển khai.","m":[],"sec":"Quản lý khẩn cấp và thiên tai"},{"c":"FMS.09.01","ch":"FMS","t":"Bệnh viện triển khai và đánh giá chương trình quản lý khẩn cấp để ứng phó với sự xuất hiện của các bệnh truyền nhiễm toàn cầu.","p":"Ngoài các trường hợp khẩn cấp và thảm họa trong cộng đồng có thể khác nhau tùy theo vị trí địa lý của bệnh\nviện, bệnh viện cũng cần có chương trình quản lý khẩn cấp đối với các bệnh truyền nhiễm toàn cầu. Toàn\ncầu hóa xã hội đã làm tăng khả năng lây lan nhanh chóng các bệnh truyền nhiễm từ quốc gia này sang quốc gia\nkhác như đã thấy trong đại dịch COVID-19. Trong đại dịch COVID-19, các bệnh viện phải đối mặt với nhu\ncầu cao chưa từng có về các dịch vụ chăm sóc sức khỏe và phải nhanh chóng triển khai chương trình quản lý\nkhẩn cấp để giải quyết cuộc khủng hoảng COVID-19. Để ứng phó hiệu quả với sự xuất hiện của các bệnh\ntruyền nhiễm toàn cầu, bệnh viện đã xây dựng một chương trình để quản lý các bệnh truyền nhiễm mới nổi\nnày.\n\nTổ chức Y tế Thế giới (WHO) đã xác định tầm quan trọng của việc phát hiện sớm các đợt bùng phát bệnh\ntruyền nhiễm và ngăn chặn tử vong, lây lan và tác động tiềm ẩn. Một yếu tố thiết yếu trong việc phát hiện và\nhạn chế sự lây lan của bệnh truyền nhiễm là truyền thông - với các cơ quan chính phủ địa phương và khu vực\nhoặc các trung tâm xuất sắc của trường đại học tham gia vào các hoạt động giám sát trên toàn thế giới nhằm\nxác định và theo dõi các bệnh truyền nhiễm mới nổi trên toàn cầu. Ví dụ về các tổ chức tham gia vào các hoạt\nđộng giám sát bao gồm Dịch vụ Phòng thí nghiệm Y tế Công cộng Vương quốc Anh, Viện Pasteur Pháp,\nMạng lưới Chương trình Đào tạo về Dịch tễ học và Can thiệp Y tế Công cộng (TEPHINET) và Trung tâm\nKiểm soát và Phòng ngừa Dịch bệnh Hoa Kỳ (CDC). Ngoài ra, các tổ chức cần kết nối với bộ phận dịch tễ\nhọc của các cơ quan y tế công cộng địa phương khi có thể.\n\nChương trình được đánh giá để đảm bảo phản ứng phù hợp khi một sự kiện thực tế xảy ra. Đánh giá liên quan\nđến các cơ quan địa phương, khu vực và/hoặc quốc gia, khi áp dụng; ví dụ, một cuộc diễn tập ứng phó toàn cộng\nđồng hoặc tham gia vào một cuộc diễn tập trên bàn do các cơ quan y tế công cộng quốc gia chỉ đạo. Nếu bệnh\nviện trải qua một sự kiện thực tế, kích hoạt chương trình của mình và tóm tắt đúng cách sau đó, thì điều này\ntương đương với một đánh giá hàng năm. Tóm tắt sau một đánh giá hàng năm hoặc sự kiện thực tế có thể xác\nđịnh các quy trình dễ bị tổn thương có thể cần được đánh giá lại.\n\nCác yếu tố đo lường được của FMS.09.01\n1.\nBệnh viện xây dựng và triển khai chương trình chuẩn bị ứng phó khẩn cấp để ứng phó với các bệnh truyền\nnhiễm toàn cầu bao gồm các nội dung sau:\n•\nQuy trình xác định thời điểm kích hoạt các quy trình quản lý khẩn cấp để ứng phó với các bệnh truyền\nnhiễm mới nổi hoặc tái phát (Xem thêm PCI.07.00, ME 1)\n•\nChiến lược truyền thông nội bộ và bên ngoài, bao gồm các cơ quan giám sát bệnh tật tại địa phương và\ntoàn cầu\n•\nXác định và phân công vai trò và trách nhiệm của nhân viên\n•\nXác định chuỗi cung ứng thay thế cho thiết bị bảo vệ cá nhân và các vật tư quan trọng khác (Xem thêm\nPCI.07.01, ME 2)\n2.\nBệnh viện triển khai các kế hoạch biên chế nhân sự khẩn cấp để đảm bảo tính liên tục của hoạt động và\ncung cấp dịch vụ chăm sóc bệnh nhân.\n3.\nBệnh viện xác định các điểm đầu tiên bệnh nhân vào hệ thống bệnh viện và có quy trình để hạn chế tiếp\ncận các điểm tiếp cận đã xác định trước. (Xem thêm PCI.07.02, ME 1)\n4.\nBệnh viện đánh giá toàn bộ chương trình ít nhất hàng năm và khi áp dụng, sẽ liên quan đến các cơ quan địa\nphương, khu vực và/hoặc quốc gia.\n5.\nCác hành động tiếp theo được xác định từ quá trình đánh giá và tóm tắt được phát triển và\nthực hiện.\n6. Bệnh viện triển khai quy trình quản lý tình trạng bệnh nhân mắc bệnh truyền nhiễm đột ngột đổ về.\n\nXây dựng và cải tạo","m":[]},{"c":"FMS.10.00","ch":"FMS","t":"Khi lập kế hoạch cho các dự án xây dựng, cải tạo và phá dỡ hoặc các hoạt động bảo trì ảnh hưởng đến việc chăm sóc bệnh nhân, tổ chức sẽ tiến hành đánh giá rủi ro trước khi xây dựng.","p":"Các hoạt động xây dựng, cải tạo, phá dỡ và bảo trì trong bệnh viện có thể tác động đến mọi người trong tổ\nchức; tuy nhiên, bệnh nhân có thể chịu tác động lớn nhất. Ví dụ, tiếng ồn và độ rung liên quan đến các hoạt\nđộng này có thể ảnh hưởng đến mức độ thoải mái của bệnh nhân và bụi và mùi có thể làm thay đổi chất\nlượng không khí, có thể gây ra mối đe dọa đến tình trạng hô hấp của bệnh nhân. Rủi ro đối với bệnh nhân,\nnhân viên, khách thăm, các thực thể kinh doanh độc lập và những người khác trong bệnh viện sẽ khác nhau\ntùy thuộc vào mức độ hoạt động xây dựng, cải tạo, phá dỡ hoặc bảo trì và tác động của nó đối với việc\nchăm sóc bệnh nhân, cơ sở hạ tầng và tiện ích. Ví dụ, hoạt động bảo trì liên quan đến khí y tế có thể ảnh\nhưởng đến việc chăm sóc bệnh nhân; tuy nhiên, việc làm lại mặt bãi đậu xe của nhân viên có thể không ảnh\nhưởng đến việc chăm sóc bệnh nhân.\n\nCác dự án phá dỡ, xây dựng, cải tạo và bảo trì thường xuyên ở bất kỳ đâu trong bệnh viện cũng có thể là rủi\nro kiểm soát nhiễm trùng lớn. Việc tiếp xúc với bụi và mảnh vụn xây dựng, cùng các mối nguy hiểm khác,\ncó thể lây truyền nhiễm trùng và có khả năng gây nguy hiểm cho sức khỏe và sự an toàn của nhân viên, bệnh\nnhân và khách đến thăm.\n\nĐể đánh giá các rủi ro liên quan đến dự án xây dựng, cải tạo hoặc phá dỡ, hoặc hoạt động bảo trì ảnh\nhưởng đến việc chăm sóc bệnh nhân, bệnh viện sẽ tập hợp các phòng ban có liên quan, bao gồm, khi cần\nthiết, đại diện từ bộ phận thiết kế dự án, quản lý dự án, kỹ thuật cơ sở, an ninh/an toàn cơ sở, phòng ngừa\nvà kiểm soát nhiễm trùng, an toàn phòng cháy chữa cháy, dọn dẹp, dịch vụ công nghệ thông tin và các phòng\nban lâm sàng và dịch vụ.\n\nRủi ro được đánh giá bằng cách tiến hành đánh giá rủi ro trước khi xây dựng, còn được gọi là PCRA, trong\nsuốt vòng đời của dự án. Đánh giá rủi ro được sử dụng để đánh giá toàn diện các rủi ro nhằm lập kế hoạch\nvà triển khai các biện pháp phòng ngừa nhằm giảm thiểu tác động của dự án đến chất lượng và sự an toàn\ncủa việc chăm sóc bệnh nhân. Ví dụ, các biện pháp giảm thiểu rủi ro hỏa hoạn và đảm bảo lối thoát an toàn\nđược triển khai khi xác định được rủi ro an toàn phòng cháy chữa cháy.\n\nNgoài ra, bệnh viện đảm bảo rằng việc tuân thủ của nhà thầu được giám sát, thực thi và ghi chép lại. Là một\nphần của đánh giá rủi ro, nguy cơ nhiễm trùng của bệnh nhân từ quá trình xây dựng được đánh giá thông\nqua đánh giá rủi ro kiểm soát nhiễm trùng, còn được gọi là ICRA.\n\nCác yếu tố đo lường được của FMS.10.00\n1. Khi lập kế hoạch cho các dự án xây dựng, cải tạo hoặc phá dỡ, hoặc các hoạt động bảo trì ảnh\nhưởng đến việc chăm sóc bệnh nhân, bệnh viện tiến hành đánh giá rủi ro trước khi xây dựng\n(PCRA) bao gồm tối thiểu các nội dung sau:\n•\nChất lượng không khí\n•\nPhòng ngừa và kiểm soát nhiễm trùng\n•\nTiện ích\n•\nTiếng ồn\n•\nRung\n•\nVật liệu và chất thải nguy hại\n•\nAn toàn cháy nổ\n•\nAn ninh\n•\nCác quy trình khẩn cấp, bao gồm các lối đi/lối thoát thay thế và khả năng tiếp cận các dịch vụ\nkhẩn cấp\n•\nCác mối nguy hiểm khác ảnh hưởng đến việc chăm sóc, điều trị và các dịch vụ\n(Xem thêm FMS.02.00, ME 1)\n2. Bệnh viện thực hiện hành động dựa trên đánh giá của mình để giảm thiểu rủi ro trong quá trình\nxây dựng, cải tạo, và các dự án phá dỡ, cũng như các hoạt động bảo trì ảnh hưởng đến việc chăm\nsóc bệnh nhân.\n3.  Bệnh viện đảm bảo rằng việc tuân thủ của nhà thầu được giám sát, thực thi và ghi chép lại.\n\nGovernance, Leadership,\nQuản trị, Lãnh\nđạo và Chỉ đạo\n\nTổng quan\nCung cấp dịch vụ chăm sóc bệnh nhân tuyệt vời đòi hỏi sự lãnh đạo hiệu quả. Sự lãnh đạo hiệu quả bắt đầu bằng\nviệc hiểu các trách nhiệm và thẩm quyền khác nhau của các cá nhân trong tổ chức và cách những cá nhân này làm\nviệc cùng nhau. Những người quản lý, điều hành và lãnh đạo một tổ chức có cả thẩm quyền và trách nhiệm. Họ\ncó trách nhiệm tuân thủ luật pháp và quy định, cũng như đáp ứng trách nhiệm của tổ chức đối với nhóm bệnh\nnhân được phục vụ.\n\nCác nhà lãnh đạo tổ chức thúc đẩy văn hóa an toàn trong toàn tổ chức. Theo thời gian, sự lãnh đạo hiệu quả giúp\nvượt qua các rào cản nhận thức và các vấn đề giao tiếp giữa các phòng ban và dịch vụ trong tổ chức, và tổ chức trở\nnên hiệu quả và hiệu suất hơn. Các dịch vụ ngày càng được tích hợp. Đặc biệt, việc tích hợp tất cả các hoạt động\ncải tiến và quản lý chất lượng trong toàn tổ chức sẽ mang lại kết quả cải thiện cho bệnh nhân.\n\nCấp I: GLD.01.00\nQuản trị\n\nCấp II: GLD.02.00\nGiám đốc điều hành\n\nCấp III: GLD.03.00 – GLD.05.03\nLãnh đạo bệnh\nThuốc\nĐiều dưỡng\nQuản lý\nKhác\n\nCấp IV: GLD.06.00 – GLD.06.02\nTrưởng phòng/Trưởng dịch vụ\nKhoa lâm\nsàng\nDịch vụ chẩn đoán\nDược\nDịch vụ bổ sung\nQuản lý dịch vụ lâm sàng và phi lâm sàng\n\nGLD.07.00 – GLD.09.00\nTổ chức và Đạo đức lâm sàng Giáo dục chuyên\ngia y tế Nghiên cứu đối tượng con người\n\nGovernance, Leadership,\n\nCác tiêu chuẩn trong chương này được nhóm lại bằng cách sử dụng hệ thống phân cấp lãnh đạo sau đây:\n\nCấp độ I: Quản trị\n\nQuản trị đề cập đến thực thể quản lý bệnh viện và có thể tồn tại trong nhiều cấu hình. Ví dụ, thực thể quản lý có\nthể là một nhóm cá nhân (như hội đồng cộng đồng), một hoặc nhiều chủ sở hữu cá nhân trong một cấu trúc công\nty hoặc trong trường hợp bệnh viện công, Bộ Y tế. Bất kỳ cá nhân hoặc thành viên hội đồng quản trị nào chịu\ntrách nhiệm cho các yêu cầu được nêu trong GLD.01.00 đều được coi là thực thể quản lý bệnh viện.\n\nCấp độ II: Tổng giám đốc điều hành\n\nNgười điều hành bệnh viện cấp cao nhất, thường được gọi là giám đốc điều hành, là một vị trí do một hoặc\nnhiều cá nhân do cơ quan quản lý lựa chọn để quản lý tổ chức hàng ngày. Trong các trung tâm y khoa học thuật,\nhiệu trưởng trường y có thể ở cấp điều hành này trong bệnh viện. GLD.02.00 mô tả trách nhiệm và kỳ vọng của\ngiám đốc điều hành.\n\nCấp độ III: Lãnh đạo bệnh viện\n\nCác tiêu chuẩn giao cho các nhà lãnh đạo bệnh viện nhiều trách nhiệm khác nhau nhằm hướng dẫn bệnh viện cùng\nnhau thực hiện sứ mệnh của mình. Thông thường, ban lãnh đạo bệnh viện bao gồm một giám đốc y khoa đại diện\ncho đội ngũ y tế của bệnh viện, một giám đốc điều dưỡng đại diện cho tất cả các cấp điều dưỡng trong bệnh viện,\ncác quản trị viên cấp cao và bất kỳ cá nhân nào khác do bệnh viện lựa chọn, chẳng hạn như giám đốc chất lượng,\ngiám đốc thông tin hoặc phó chủ tịch phụ trách nhân sự. Ở các bệnh viện lớn hơn với các cấu trúc tổ chức khác\nnhau, chẳng hạn như các bộ phận, ban lãnh đạo bệnh viện có thể bao gồm các nhà lãnh đạo của các bộ phận này.\nMỗi bệnh viện xác định ban lãnh đạo bệnh viện và các tiêu chuẩn GLD.03.00 đến GLD.05.03 mô tả trách nhiệm\ncủa nhóm này.\n\nLưu ý: GLD.06.00 mô tả trách nhiệm của các nhà lãnh đạo dịch vụ lâm sàng; tuy nhiên, họ có thể được tổ\nchức chính thức hoặc không chính thức. Trong các trung tâm y khoa học thuật, nhà lãnh đạo giáo dục y khoa\nvà nhà lãnh đạo nghiên cứu lâm sàng có thể là một phần của ban lãnh đạo bệnh viện.\n\nCấp độ IV: Trưởng phòng/Trưởng dịch vụ\n\nĐể cung cấp dịch vụ lâm sàng và quản lý tổ chức hiệu quả và hiệu suất hàng ngày, các bệnh viện thường được chia\nthành các nhóm nhỏ gắn kết như khoa, dịch vụ hoặc đơn vị, mỗi nhóm dưới sự chỉ đạo của một hoặc nhiều trưởng\nkhoa/dịch vụ.","m":[],"sec":"Xây dựng và cải tạo"},{"c":"GHI.01.00","ch":"GHI","t":"Các nhà lãnh đạo bệnh viện đảm bảo rằng các chiến lược về môi trường được đưa vào chính thức và được thực hiện như một phần của hoạt động và quản lý của tổ chức.","p":"Để khử cacbon và tăng khả năng phục hồi của bệnh viện, các hành động phải được thực hiện ở mọi cấp độ của tổ\nchức. Điều này đòi hỏi một chiến lược, sự quản lý, trách nhiệm giải trình và sự lãnh đạo hiệu quả ở cấp lãnh đạo\nbệnh viện và hội đồng quản trị. Điều này sẽ cho phép tổ chức thực hiện những điều sau:\n•\nPhản hồi luật pháp và quy định của quốc gia liên quan đến các vấn đề về khí hậu và môi trường.\n•\nXác định các ưu tiên cho tổ chức.\n•\nTruyền cảm hứng và hỗ trợ văn hóa tổ chức có tính đến tính bền vững của môi trường và tạo ra ý thức sở\nhữu và mục tiêu chung bằng cách thường xuyên truyền đạt về vấn đề này trong toàn bệnh viện.\n•\nThu hút tất cả các bên liên quan vào quá trình này và truyền đạt rõ ràng vai trò cụ thể của họ là gì, vai trò đó\nảnh hưởng như thế nào đến công việc và hoạt động hàng ngày của họ và những kết quả tích cực nào được\nmong đợi.\n•\nThu hút các cơ quan quản lý bệnh viện để đảm bảo báo cáo, giám sát và cải thiện các chiến lược.\n\nNgày càng có nhiều bằng chứng chứng minh tác động của biến đổi khí hậu và các sự kiện khí hậu đột phá đối với\nsức khỏe và việc cung cấp dịch vụ chăm sóc sức khỏe. Do đó, một phần trong sứ mệnh của bệnh viện là chống lại\nnhững tác động tiêu cực của biến đổi khí hậu và hướng tới các dịch vụ bền vững hơn bằng cách giải quyết vấn đề\nnày như một phần không thể thiếu trong việc cung cấp dịch vụ chăm sóc sức khỏe. Ngoài việc khử cacbon cho ngành\nvà giúp ngành này phục hồi tốt hơn, nhiều lợi ích chung đã được xác định, bao gồm những tác động tích cực đến\nsức khỏe, trải nghiệm của bệnh nhân và hiệu suất hoạt động. Một loạt bằng chứng ngày càng tăng cũng chứng minh\nsự liên quan của các sáng kiến về tính bền vững với chất lượng chăm sóc và tính đầy đủ cho sự an toàn của bệnh\nnhân. Ngoài ra, các sáng kiến về tính bền vững về môi trường mang lại cơ hội tiết kiệm tài chính và\nđã được xác định là một cách hiệu quả để hỗ trợ tính bền vững về tài chính lâu dài của bệnh viện. Loại can thiệp,\ntác động và lợi ích sẽ phụ thuộc vào quy mô, bối cảnh và các can thiệp đã có của bệnh viện.\n\nCó thể triển khai nhiều hành động và quy trình ở cấp lãnh đạo và hội đồng quản trị bệnh viện để thúc đẩy quá trình\nnày. Ví dụ về các hành động như vậy bao gồm:\n•\nPhản hồi chính thức đối với luật pháp và quy định cụ thể của từng quốc gia liên quan đến các vấn đề về khí\nhậu và môi trường.\n•\nChính thức đưa các mục tiêu về tính bền vững của môi trường vào các tài liệu chính thức và công khai, bao\ngồm tuyên bố sứ mệnh, giá trị, điều lệ và các tài liệu quản trị khác của tổ chức (điều này củng cố trách nhiệm\ngiải trình và tạo ra cảm giác về mục tiêu chung trong toàn bộ tổ chức).\n•\nÁp dụng các chỉ số để đo lường, theo dõi và báo cáo tiến độ thông qua các khuôn khổ hiện có để giám sát và\nđiều chỉnh theo thời gian.\n•\nTăng hiệu quả và trách nhiệm giải trình tích cực cũng như sự tham gia của ban quản lý cấp cao thông qua việc\nbổ nhiệm một cá nhân hoặc một nhóm người chuyên trách để giám sát quá trình này.\n\nNgoài việc chỉ định những người này, điều cần thiết là phải hỗ trợ họ trong công việc và đặt ra các mục tiêu kết hợp\ncác quy định về môi trường để đảm bảo một chiến lược hiệu quả. Vai trò của họ là xây dựng một kế hoạch hành\nđộng bao gồm các mục tiêu ngắn hạn, trung hạn và dài hạn; xác định các nguồn lực cần thiết; giám sát việc phát triển,\ntriển khai và đánh giá chiến lược; và làm việc và giao tiếp với các bên liên quan có liên quan. Người này phải có kinh\nnghiệm giáo dục và/hoặc chuyên môn phù hợp để đảm nhận vai trò như vậy.\n\nChapter © 2024 The Joint Commission on behalf of Uỷban chung Quốc tế,\nChapter © 2024 The Joint Commission on behalf of Uỷban chung Quốc tế,\n\nCác yếu tố đo lường được của GHI.01.00\n1. D Các nhà lãnh đạo bệnh viện đưa tính bền vững về môi trường và chăm sóc ít carbon và phục hồi vào chương\ntrình nghị sự của hội đồng quản trị để thảo luận ít nhất một lần một năm, với báo cáo về tiến độ, tuyên bố về\ncác nguồn lực được phân bổ và đánh giá việc thực hiện các chiến lược. Biên bản phản ánh các hành động đã\nthực hiện và bất kỳ hoạt động theo dõi nào đối với các hành động đó.\n2. D Tiến độ thực hiện các chiến lược về môi trường được đưa vào báo cáo thường niên của tổ chức để công\nchúng có thể nhìn thấy và chịu trách nhiệm rộng rãi hơn đối với cộng đồng và các bên liên quan khác.\n3. Các nhà lãnh đạo bệnh viện bổ nhiệm hoặc chỉ định và đánh giá hàng năm hiệu suất của một người giữ vai trò\nlãnh đạo, người báo cáo với hội đồng quản trị (ví dụ: Giám đốc Phát triển Bền vững) để đảm bảo rằng các\nchiến lược về môi trường là một phần trong các ưu tiên của tổ chức và được thực hiện hiệu quả trong các quy\ntrình theo dõi và quản trị. (Xem thêm GLD.06.00, ME 1)\n4. Người được bổ nhiệm hoặc chỉ định giữ vai trò lãnh đạo chịu trách nhiệm về những nội dung sau:\n•\nXác định kế hoạch, chiến lược và mục tiêu phát triển bền vững của bệnh viện, sau khi tham vấn với các\nbên liên quan\n•\nGiám sát việc thực hiện các quy trình liên quan đến phát triển bền vững về môi trường\n•\nBáo cáo với các nhà lãnh đạo và ban quản trị bệnh viện để trình bày tiến độ thực hiện và hành động về các\nđiểm thảo luận đã nêu\n•\nBiên soạn các báo cáo và tài liệu truyền thông cho các bên liên quan có liên quan\n\nSự tham gia và trao quyền của nhân viên","m":[],"sec":"Quản trị, Theo dõi và Báo cáo"},{"c":"GHI.02.00","ch":"GHI","t":"Lãnh đạo bệnh viện thiết lập các cơ chế để nâng cao nhận thức và thu hút và đào tạo nhân viên về biến đổi khí hậu và sức khỏe trên toàn tổ chức.","p":"Nhân viên có vai trò trong quá trình chuyển đổi sang dịch vụ chăm sóc sức khỏe ít carbon, bền vững và có khả năng\nphục hồi. Để hỗ trợ nhân viên của mình trong việc triển khai các quy định và thông lệ mới hoặc khác, các nhà lãnh\nđạo bệnh viện phải cung cấp kiến thức và công cụ để tạo điều kiện cho quyền sở hữu và biến nhân viên thành tác\nnhân thay đổi.\n\nCó thể sử dụng hai cơ chế chính để thu hút nhân viên tổ chức tham gia vào các sáng kiến về biến đổi khí hậu:\n•\nVăn hóa tổ chức thuận lợi và hấp dẫn: Văn hóa tổ chức đại diện cho “tư duy, niềm tin và giá trị mà các thành\nviên trong tổ chức chia sẻ chung, và định hình nên hành vi [và] thông lệ. của tổ chức” (Prajogo và McDermott,\n2005). Lãnh đạo tốt và tập trung vào khách hàng (bệnh nhân) là những thành phần thiết yếu để thu hút nhân\nviên và tập hợp họ hướng tới một mục tiêu chung. Do đó, các nhà lãnh đạo bệnh viện nên nhấn mạnh rằng\nchiến lược hướng tới dịch vụ chăm sóc sức khỏe bền vững với môi trường là một nỗ lực chung và có thể góp\nphần cải thiện kết quả sức khỏe và trải nghiệm của bệnh nhân. Điều này có thể đạt được thông qua các hoạt\nđộng giao tiếp có liên quan và thường xuyên từ các nhà lãnh đạo bệnh viện đến nhân viên, cũng như các cơ\nchế cho phép nhân viên chia sẻ ý tưởng và tích cực đóng góp vào chiến lược phát triển bền vững. Bối cảnh\nbệnh viện là một môi trường phức tạp và khó lường, tính linh hoạt và tập trung vào các mối quan hệ là những\nnăng lực chính để duy trì văn hóa tổ chức hiệu quả.\n•\nĐào tạo và giáo dục là chìa khóa để cung cấp kiến thức, công cụ, năng lực và hướng dẫn cho nhân viên. Một\nsố nội dung sẽ giống nhau đối với tất cả nhân viên, chẳng hạn như kiến thức cơ bản về khí hậu và\n•\nsức khỏe, và cách đưa kiến thức này vào các mục tiêu của bệnh viện. Các khóa đào tạo đó nên bao gồm nội\ndung liên quan đến bối cảnh của bệnh viện, bao gồm tác động của khí hậu tại địa phương hoặc khu vực và các\nkết quả liên quan đến sức khỏe, các kịch bản môi trường tiềm ẩn đối với bệnh viện và các điểm yếu được xác\nđịnh trong nhóm bệnh nhân của bệnh viện. Một số khóa đào tạo có thể được nhắm mục tiêu nhiều hơn để\ntập trung vào các vai trò và thực hành cụ thể để điều chỉnh hoặc triển khai, như trong các ví dụ sau:\n\nChapter © 2024 The Joint Commission on behalf of Uỷban chung Quốc tế,\nChapter © 2024 The Joint Commission on behalf of Uỷban chung Quốc tế,\n\no\nNhân viên lâm sàng sẽ tìm hiểu về các giải pháp thay thế cho các sản phẩm tạo ra nhiều chất thải (ví dụ:\ngăng tay không phẫu thuật) hoặc khí gây mê có cường độ phát thải carbon cao (ví dụ: desflurane).\no\nQuản lý phòng ban sẽ tìm hiểu các năng lực lãnh đạo cụ thể để hỗ trợ họ và nhóm của họ giảm thiểu chất\nthải và đưa các hành vi bền vững vào hoạt động hàng ngày của họ.\no\nNhân viên vệ sinh sẽ tìm hiểu về tác động của hóa chất được sử dụng trong các sản phẩm vệ sinh đối với\nsức khỏe và môi trường cũng như về hiệu quả của các giải pháp thay thế.\n“Đào tạo xanh” và sự tham gia có thể mang lại những kết quả có lợi khác cho tổ chức, bao gồm:\n• Tạo cảm giác thử thách, thúc đẩy nhân viên tham gia\n• Sự hài lòng hơn trong công việc khi được nhà tuyển dụng hỗ trợ\n• Trải nghiệm nghề nghiệp thỏa đáng cho nhân viên\n• Đáp ứng nhu cầu của các chuyên gia trẻ tuổi muốn biết tổ chức của họ tích cực tham gia vào các vấn đề này\nvà giúp giữ chân lực lượng lao động\n\nDo đó, họ có thể thúc đẩy tinh thần làm việc của công ty, giảm tỷ lệ luân chuyển nhân sự và tăng hiệu suất\nchung cũng như chất lượng dịch vụ của tổ chức.\n\nCác yếu tố đo lường được của GHI.02.00\n1.\nTất cả nhân viên y tế và phi y tế trên toàn bệnh viện đều trải qua các buổi đào tạo hàng năm cụ thể,\nnhằm cung cấp kiến thức cơ bản về biến đổi khí hậu, tác động của nó đến sức khỏe con người và các\nthông lệ tốt mà họ có thể thực hiện để chăm sóc sức khỏe bền vững và phục hồi về mặt môi trường.\n2.\nLãnh đạo bệnh viện truyền đạt cho nhân viên về tính bền vững của môi trường và các mục tiêu và hoạt\nđộng chăm sóc ít carbon và phục hồi của tổ chức.\n3.\nMột quy trình được triển khai để thu thập ý tưởng của nhân viên, được người đứng đầu xem xét về tính\nbền vững để xác định các sáng kiến và ưu tiên mới tiềm năng.\n4.\nD Một mô-đun về biến đổi khí hậu, tính bền vững của môi trường và chăm sóc ít carbon và phục hồi\nđược đưa vào định hướng/nhập môn cho nhân viên mới. (Xem thêm SQE.01.06, ME 1)\n\nSử dụng Tài nguyên Môi trường, Hoạt\nđộng Xanh và Quy trình","m":[],"sec":"Sự tham gia và trao quyền của nhân viên"},{"c":"GHI.03.00","ch":"GHI","t":"Các nhà lãnh đạo bệnh viện xây dựng và bắt đầu thực hiện kế hoạch để đo lường và giảm thiểu việc sử dụng vật liệu và tài nguyên môi trường, bao gồm năng lượng, nước và khí thải.","p":"Bệnh viện phải làm việc trên tất cả các phạm vi phát thải để giải quyết vấn đề khử cacbon và tăng khả năng phục hồi\ncũng như tính bền vững của môi trường. Điều cần thiết là phải xem xét việc sử dụng tài nguyên thiên nhiên cũng như\nvật liệu. Để đạt được mục đích này, một trong những nhiệm vụ chính của người đứng đầu được chỉ định về tính bền\nvững của môi trường là phải lập kế hoạch. Điều này có thể đạt được thông qua các bước sau:\n•\nThiết lập và hiểu được đường cơ sở cho phạm vi đánh giá và hành động\n•\nXác định và ưu tiên các biện pháp can thiệp ngắn hạn và dài hạn\n•\nLập kế hoạch hành động và cải tiến\n•\nĐo lường, theo dõi, đánh giá và báo cáo các cải tiến hướng tới các mục tiêu đã xác định\n\nĐối với bất kỳ bệnh viện nào, nguồn gốc của khí thải carbon dioxide hoặc khí thải nhà kính (GHG) có thể được phân\nloại thành ba phạm vi:\n\nChapter © 2024 The Joint Commission on behalf of Uỷban chung Quốc tế,\nChapter © 2024 The Joint Commission on behalf of Uỷban chung Quốc tế,\n\n•\nPhạm vi phát thải 1 là từ các nguồn do tổ chức sở hữu hoặc kiểm soát trực tiếp (ví dụ: quá trình đốt\nnhiên liệu tại chỗ trong lò hơi, lò nung, xe cộ).\n•\nPhạm vi 2 là từ việc mua và sử dụng điện, hơi nước, hệ thống sưởi ấm và làm mát được tạo ra ở nơi\nkhác. Khi sử dụng năng lượng, tổ chức phải chịu trách nhiệm gián tiếp cho việc phát thải các khí nhà\nkính này.\n•\nPhạm vi phát thải 3 bao gồm các khí thải gián tiếp do chuỗi giá trị của tổ chức gây ra, trong các hoạt\nđộng thượng nguồn và hạ nguồn của tổ chức. Trong số những hoạt động khác, điều này bao gồm hàng\nhóa và dịch vụ đã mua, vận chuyển và phân phối (thượng nguồn và hạ nguồn) cũng như xử lý chất\nthải.\nBệnh viện có thể tiến hành đánh giá dấu chân carbon để xác định các \"điểm nóng\" về phát thải cần có hành\nđộng khử cacbon sâu hơn. Có một số công cụ tính dấu chân carbon dành cho lĩnh vực chăm sóc sức khỏe,\ndành cho các bệnh viện ở các quốc gia có thu nhập thấp đến cao. Việc thu thập dữ liệu và hoàn thành toàn\nbộ quy trình có thể mất vài tháng. Do đó, chúng tôi đặc biệt khuyến nghị triển khai các biện pháp giúp đẩy\nnhanh quá trình tham gia và khử cacbon trước khi hoàn tất đánh giá dấu chân carbon.\nCác lĩnh vực chính của quản lý tài nguyên được trình bày dưới đây:\nSản xuất điện và điện là điều cần thiết để vận hành bất kỳ cơ sở chăm sóc sức khỏe nào và cung cấp dịch vụ\nchăm sóc an toàn và chất lượng cao. Tuy nhiên, biến đổi khí hậu (bao gồm cả thông qua các sự kiện khí hậu\nđột phá) sẽ tác động tiêu cực đến khả năng tiếp cận điện và buộc các tổ chức phải xem xét cách sản xuất và\nsử dụng năng lượng. Việc lập kế hoạch và can thiệp tốt có thể giúp các bệnh viện có khả năng phục hồi tốt\nhơn trước các sự kiện như vậy đồng thời giảm lượng khí thải carbon của họ:\n•\nMột số cơ sở đầu tư vào sản xuất điện tại chỗ, thay vì mua năng lượng đó thông qua lưới điện. Lợi\ních chung của sản xuất điện tại chỗ là giảm chi phí năng lượng, giảm lượng khí thải nhà kính (đặc\nbiệt là trong trường hợp sản xuất năng lượng tái tạo) và cải thiện độ tin cậy của nguồn cung cấp.\n•\nTất cả các tổ chức nên hướng tới mục tiêu tiêu thụ và sản xuất năng lượng từ các nguồn năng\nlượng tái tạo.\n•\nNăng lượng tái tạo có nguồn gốc từ các nguồn tự nhiên được bổ sung với tốc độ cao hơn mức\ntiêu thụ. Các nguồn năng lượng tái tạo phổ biến là ánh sáng mặt trời, gió, năng lượng địa nhiệt,\nthủy điện,\n•\nnăng lượng đại dương và năng lượng sinh học. Mặt khác, nhiên liệu hóa thạch (than, dầu và khí\nđốt) là nguồn tài nguyên không tái tạo, mất hàng trăm triệu năm để hình thành và có thể gây ra\nkhí thải nhà kính có hại, chẳng hạn như carbon dioxide.\n•\nViệc xem xét lại các tòa nhà và cơ sở hạ tầng, bao gồm kiến trúc, thiết kế dịch vụ và sử dụng không\ngian, cũng sẽ góp phần rất lớn vào việc tối ưu hóa việc sử dụng năng lượng đồng thời giúp bệnh viện\nphục hồi và bền vững hơn.\n\nBiến đổi khí hậu đang đẩy nhanh các mối nguy hiểm liên quan đến nước và tình trạng khan hiếm nước. Mặc\ndù một số khu vực có thể bị ảnh hưởng nhiều hơn những khu vực khác, các tổ chức trên toàn cầu phải triển\nkhai các giải pháp để bảo tồn nguồn nước. Các cơ sở chăm sóc sức khỏe quan tâm trực tiếp đến các vấn đề\nvề an toàn nước vì chúng sẽ tác động đến việc cung cấp dịch vụ chăm sóc sức khỏe, vệ sinh và vệ sinh môi\ntrường trong tổ chức. Do đó, các bệnh viện được khuyến nghị đo lường mức tiêu thụ nước và triển khai các\ngiải pháp để tối ưu hóa nguồn cung cấp và bảo tồn nước. Cơ sở hạ tầng thoát nước thải tốt và việc sử dụng\nnước thải an toàn cũng phải được quản lý, vì chúng có thể tăng khả năng phục hồi của bệnh viện đồng thời\ngóp phần đạt được các mục tiêu về nước, vệ sinh và vệ sinh (WASH).\n\nGiảm phát thải carbon cũng có thể xảy ra trong quá trình cung cấp dịch vụ chăm sóc sức khỏe. Mô hình chăm\nsóc ít carbon là một hình thức cung cấp dịch vụ chăm sóc tạo ra ít khí thải carbon hơn so với các phương án\nthay thế hiện có. Điều này có nghĩa là tác động của khí thải carbon trong việc cung cấp dịch vụ chăm sóc đã\nđược ước tính là có lợi cho các dịch vụ hoặc can thiệp tạo ra ít khí thải carbon hơn và giảm mức sử dụng\nnăng lượng. Mô hình cung cấp dịch vụ chăm sóc ít carbon sẽ ngăn ngừa bệnh tật tốt hơn, thiết kế và cung\ncấp dịch vụ tinh gọn hơn và thúc đẩy việc sử dụng các công nghệ ít carbon hơn (ví dụ: chăm sóc sức khỏe từ\nxa, dựa trên ứng dụng). Việc giảm phát thải carbon này cũng áp dụng cho dược phẩm, máy xông khí dung và\nkhí gây mê. Ví dụ, Scotland đã cấm sử dụng desflurane do mối đe dọa ngày càng tăng đối với môi trường.\nNgoài ra, việc xanh hóa các hoạt động phòng phẫu thuật có thể giảm mức sử dụng năng lượng, mức sử dụng\nvật tư và lượng chất thải phát sinh, từ đó tiết kiệm tài chính.\n\nChapter © 2024 The Joint Commission on behalf of Uỷban chung Quốc tế,\nChapter © 2024 The Joint Commission on behalf of Uỷban chung Quốc tế,\n\nNguồn cung cấp, và do đó, chất thải và khí thải từ dược phẩm và các hóa chất khác được sử dụng để điều trị cũng nên giảm\nthông qua các hoạt động kê đơn. Nó bao gồm việc cung cấp thông tin cho bệnh nhân và nhân viên lâm sàng về phương pháp\nđiều trị tốt nhất, với việc sử dụng liều thấp nhất có hiệu quả trong thời gian ngắn nhất, bao gồm các loại thuốc có lượng khí\nthải carbon nhỏ nhất. Tối ưu hóa thuốc cũng bao gồm việc giải quyết việc kê đơn không cần thiết, giúp giảm lỗi. Các đơn\nthuốc ít carbon cũng bao gồm việc sử dụng các phương pháp thay thế như liệu pháp tâm lý, kê đơn xanh, kê đơn xã hội và kê\nđơn theo lối sống.\n\nQuản lý cơ sở vật chất mềm, bao gồm các hoạt động vệ sinh, dịch vụ giặt là và khăn trải giường, cũng như quản lý chất thải,\ncũng mang đến nhiều cơ hội để giảm việc sử dụng và lãng phí vật liệu, năng lượng và hóa chất. Ví dụ, việc vệ sinh có thể trở\nnên không có hóa chất bằng cách sử dụng cây lau nhà sợi nhỏ cải tiến và kỹ thuật vệ sinh được điều chỉnh. Phương pháp này\ncó thể được áp dụng toàn bộ hoặc một phần tùy thuộc vào khu vực của bệnh viện và các vấn đề liên quan đến an toàn. Các\nlợi ích bao gồm tiết kiệm chi phí, giảm lượng carbon, giảm độc tính của nước thải và cải thiện sức khỏe cũng như tinh thần\ncủa bệnh nhân và nhân viên do giảm các bệnh về đường hô hấp do các sản phẩm hóa học gây ra.\n\nĐối với tất cả những điều trên, các giải pháp thay thế vẫn tiếp tục xuất hiện và cần có những cách tiếp cận sáng tạo để tiếp\ntục nỗ lực này.\n\nCác yếu tố đo lường được của GHI.03.00\n1. D Các nhà lãnh đạo và quản lý bệnh viện xây dựng một kế hoạch có thể đo lường được bằng văn bản bao\ngồm các mục tiêu và việc giám sát các mục tiêu đó để giảm thiểu chất thải, lượng khí thải carbon và việc sử\ndụng các nguồn tài nguyên môi trường.\n2. D Tỷ lệ năng lượng tái tạo (mua hoặc tự sản xuất) so với tổng lượng năng lượng tiêu thụ được xác định và\nbáo cáo lên hội đồng quản trị hàng năm.\n3. Các nhà lãnh đạo bệnh viện thực hiện các hành động để tối ưu hóa việc bảo tồn nước và báo cáo lượng nước\nbảo tồn lên hội đồng quản trị hàng năm.\n4. Các nhà lãnh đạo và quản lý bệnh viện có thể chứng minh tiến độ hàng năm liên quan đến việc giảm lượng\nkhí thải carbon hoặc tác động tiêu cực đến môi trường của các hoạt động trong ít nhất một trong các lĩnh vực\nquản lý cơ sở vật chất mềm sau:\n•\nQuản lý chất thải\n•\nThực hành vệ sinh\n•\nDịch vụ giặt là và khăn trải giường\n5. Các nhà lãnh đạo và quản lý bệnh viện góp phần giảm cường độ carbon của thực phẩm và nguồn cung cấp\ndịch vụ ăn uống; ví dụ, bằng cách tìm nguồn cung ứng ít nhất 50% thực phẩm được sản xuất tại địa phương\nbất cứ khi nào có thể và bằng cách cung cấp các lựa chọn dành cho người ăn chay hàng ngày.\n6. Các hoạt động lâm sàng được đánh giá để giảm tác động đến môi trường.\n\nMua sắm và chuỗi cung ứng","m":[],"sec":"Sử dụng Tài nguyên Môi trường, Hoạt động Xanh và Quy trình"},{"c":"GHI.04.00","ch":"GHI","t":"Lãnh đạo bệnh viện thực hiện các hành động nhằm giảm tác động môi trường của chuỗi cung ứng trên mọi hoạt động và xác định các lĩnh vực cần giảm việc sử dụng vật tư không cần thiết trong bệnh viện.","p":"Người ta ước tính rằng thuốc men, thiết bị y tế và các chuỗi cung ứng khác có thể chiếm từ 60% đến 80% lượng khí thải\ncarbon của bệnh viện. Điều này bao gồm sản xuất, vận chuyển, sử dụng và thải bỏ hàng hóa và dịch vụ. Tuy nhiên, mặc dù\nnhững khí thải đó là gián tiếp, bệnh viện có thể đóng vai trò tích cực trong việc giảm chúng. Ví dụ, điều này có thể đạt được\nbằng cách cải thiện cách sử dụng tài nguyên (ví dụ, giảm, tái sử dụng hoặc thậm chí tránh), thay thế cho các sáng kiến ít carbon\nvà/hoặc có thể tái sử dụng, tìm nguồn cung ứng tại địa phương, làm việc với các nhà cung cấp để đặt mục tiêu và tận dụng\nsức mua của họ để yêu cầu các sản phẩm bền vững hơn.\n\nChapter © 2024 The Joint Commission on behalf of Uỷban chung Quốc tế,\nChapter © 2024 The Joint Commission on behalf of Uỷban chung Quốc tế,\n\nNgày càng có nhiều sáng kiến quốc tế hướng đến mục tiêu thúc đẩy mua sắm bền vững trong lĩnh vực chăm sóc\nsức khỏe và hướng dẫn các bệnh viện áp dụng các quy trình và hoạt động bền vững. Các sáng kiến này, được\nminh họa bằng nhiều ví dụ và nghiên cứu điển hình, xác định các lĩnh vực cần thực hiện sau:\n•\nGiảm việc sử dụng các nguồn lực có thể tránh được (ví dụ: giảm việc sử dụng găng tay không phẫu thuật\nkhi không cần thiết cho mục đích kiểm soát nhiễm trùng).\n•\nCải thiện và tối ưu hóa việc sử dụng thiết bị hiện tại (ví dụ: tiến hành đánh giá hoặc phân tích vòng đời để\ntối ưu hóa việc sử dụng lâu dài các hệ thống hình ảnh và các thiết bị điều trị khác). Đánh giá vòng đời cũng\ncó thể hỗ trợ việc ra quyết định khi so sánh tác động môi trường của các mặt hàng dùng một lần và các mặt\nhàng tái sử dụng, cũng như tiết kiệm chi phí liên quan.\nViệc xác định các nguồn cung cấp không cần thiết và có thể tránh được có thể thực hiện dưới nhiều hình thức\nkhác nhau và phải chứng minh được những nỗ lực đáng tin cậy. Ví dụ: các nỗ lực xác định có thể được chứng\nminh thông qua các cuộc kiểm toán và đánh giá liên quan, các cuộc thảo luận như đã ghi trong biên bản cuộc họp\nvà nghiên cứu về các sáng kiến tương tự tại các bệnh viện hoặc tổ chức khác. Việc xác định sẽ dẫn đến việc ưu\ntiên và chuyển thành các hành động để thực hiện.\nNgoài việc khử cacbon, điều này có thể dẫn đến cải thiện trải nghiệm của bệnh nhân và tiết kiệm tài chính.\nCác yếu tố đo lường được của GHI.04.00\n1. Tiêu chí D về tính bền vững về khí hậu và môi trường được đưa vào hướng dẫn mua sắm của bệnh\nviện. (Xem thêm GLD.05.02, ME 3)\n2. Đối với bất kỳ hợp đồng mới nào với nhà cung cấp hoặc nhà cung cấp, người quản lý phòng ban sẽ ưu\ntiên các nhà cung cấp và nhà cung cấp có mục tiêu về tính bền vững và giảm phát thải carbon. (Xem\nthêm GLD.05.02, ME 3)\n3. Lãnh đạo bệnh viện và người quản lý phòng ban xác định các cơ hội để tối ưu hóa các quy trình trong\nbệnh viện bằng cách xác định các nguồn cung cấp không cần thiết và/hoặc có thể tránh được trong ít\nnhất ba lĩnh vực sau:\n•\nDược phẩm và các hóa chất khác được sử dụng để điều trị\n•\nHóa chất được sử dụng cho mục đích khử trùng, khử trùng và làm sạch\n•\nThực phẩm và sản phẩm nông nghiệp\n•\nThiết bị y tế\n•\nThiết bị và dụng cụ bệnh viện\n4. Lãnh đạo bệnh viện và người quản lý phòng ban thực hiện các hành động để đánh giá lợi ích của các\nmặt hàng có thể tái sử dụng thay vì các vật liệu dùng một lần trong các lĩnh vực lâm sàng và phi lâm\nsàng. (Xem thêm PCI.03.01, ME 1)\nKhả năng phục hồi của cơ sở hạ tầng và dịch vụ","m":[],"sec":"Mua sắm và chuỗi cung ứng"},{"c":"GHI.05.00","ch":"GHI","t":"Các nhà lãnh đạo bệnh viện đánh giá các rủi ro và kịch bản về môi trường có thể ảnh hưởng đến việc cung cấp dịch vụ, hoạt động của bệnh viện và số lượng bệnh nhân, với các kế hoạch tuân thủ các khuyến nghị và quy tắc về chuẩn bị ứng phó khẩn cấp tại địa phương, bao gồm cả những quy định theo yêu cầu của phạm vi bảo hiểm tài sản.","p":"Khủng hoảng khí hậu được coi là mối đe dọa lớn nhất đối với sức khỏe con người trong thế kỷ 21. Nó gây ra sự gia tăng\ncác bệnh không lây nhiễm và truyền nhiễm, tác động tiêu cực đến các yếu tố xã hội và môi trường quyết định sức khỏe và\ngây ra các sự kiện khí hậu gây gián đoạn (ví dụ, lũ lụt, cháy rừng, lở đất,\ngió mạnh), có thể ảnh hưởng trực tiếp đến việc cung cấp dịch vụ chăm sóc sức khỏe khi nào và ở đâu chúng xảy\nra. Ví dụ, hậu quả có thể bao gồm những điều sau:\n•\nNhu cầu về dịch vụ chăm sóc sức khỏe tăng đột ngột nếu cộng đồng xung quanh bị ảnh hưởng trực\ntiếp\n•\nThiệt hại về cơ sở hạ tầng và trang thiết bị của bệnh viện\n\nChapter © 2024 The Joint Commission on behalf of Uỷban chung Quốc tế,\nChapter © 2024 The Joint Commission on behalf of Uỷban chung Quốc tế,\n\n• Cắt điện\n• Sự gián đoạn trong chuỗi cung ứng\n\nBệnh viện đóng vai trò độc đáo và thiết yếu đối với cộng đồng khi đối mặt với những mối nguy hiểm đó và cần có khả năng\ncung cấp dịch vụ chăm sóc liên tục trong những tình huống khẩn cấp đó.\n\nDựa trên các khuôn khổ hiện có, bệnh viện nên cân nhắc năm lĩnh vực sau để lập kế hoạch cho mọi tình huống, điều chỉnh\ncơ sở hạ tầng và dịch vụ của mình, đồng thời tăng cường khả năng phục hồi:\n• Đánh giá rủi ro về khí hậu và mức độ dễ bị tổn thương của cộng đồng\n• Sử dụng đất, thiết kế tòa nhà và bối cảnh pháp lý\n• Lập kế hoạch bảo vệ cơ sở hạ tầng và khả năng phục hồi\n• Lập kế hoạch cung cấp dịch vụ chăm sóc lâm sàng thiết yếu\n• Bảo vệ môi trường và thích ứng với hệ sinh thái\n\nSổ đăng ký rủi ro của bệnh viện hoặc tài liệu tương đương ghi lại mọi rủi ro đe dọa tổ chức và các mục tiêu của tổ chức.\nChúng có thể bao gồm hoặc cần tuân thủ các hướng dẫn chuẩn bị ứng phó khẩn cấp tại địa phương hoặc phạm vi bảo\nhiểm tài sản. Do bản chất toàn cầu của tác động của biến đổi khí hậu, các sự kiện gây gián đoạn môi trường nên được đưa\nvào sổ đăng ký rủi ro của tất cả các bệnh viện.\n\nCác sự kiện gây gián đoạn khí hậu này được dự đoán sẽ xảy ra thường xuyên hơn và ở những địa điểm mà trước đây chúng\nchưa từng xảy ra. Do đó, các rủi ro và tình huống nên được đánh giá lại sau mỗi ba năm để điều chỉnh và lập kế hoạch cho\nphù hợp.\n\nCác yếu tố đo lường được của GHI.05.00\n1. D Tác động của biến đổi khí hậu được đưa vào sổ đăng ký rủi ro của bệnh viện hoặc tài liệu tương đương.\n2. D Các nhà lãnh đạo bệnh viện xây dựng kế hoạch hành động thích ứng bằng văn bản để giảm thiểu các mối nguy\nhiểm và rủi ro liên quan đến khí hậu hiện tại và tương lai dựa trên thông tin gần đây (tức là trong vòng ba năm\nqua) và tiến triển theo các mục tiêu đã thống nhất của tổ chức. (Xem thêm FMS.09.00, ME 1 và 2)\n3. D Đánh giá các rủi ro, kịch bản và điểm yếu về môi trường trong cộng đồng được thực hiện ba năm một lần. Kết\nquả được trình bày trong báo cáo và thông báo cho kế hoạch hành động thích ứng, được cập nhật cho phù hợp.\n(Xem thêm FMS.09.00, ME 3)\n4. D Các nhà lãnh đạo bệnh viện xây dựng các chương trình chuẩn bị cho các kịch bản thời tiết bất lợi và các sự kiện\ngây gián đoạn. Kế hoạch chuẩn bị được thử nghiệm và cập nhật hàng năm và bao gồm các biện pháp được thực\nhiện để đào tạo nhân viên ứng phó với các kịch bản này. (Xem thêm FMS.02.00, ME 1; FMS.09.00, ME 1)\n\nSPhần V: Tiêu chuẩn của Trung tâm Y tế Học Thuật\nPhần V:\nTiêu chuẩn của\ntrung tâm Y tế\nHọc thuật\n\nTiêu chuẩn của Trung tâm Y tế\nHọc thuật\nTiêu chuẩn Chương trình nghiên cứu đối tượng con người (HRP) và Giáo dục chuyên gia y khoa (MPE) dành cho các\ntrung tâm y khoa hàn lâm đã được xây dựng và công bố lần đầu tiên vào năm 2012 để ghi nhận nguồn lực độc đáo mà các\ntrung tâm này đại diện cho giáo dục chuyên gia y khoa và nghiên cứu đối tượng con người trong cộng đồng và quốc gia\ncủa họ. Các tiêu chuẩn này cũng đưa ra khuôn khổ để đưa giáo dục y khoa và nghiên cứu đối tượng con người vào các\nhoạt động về chất lượng và an toàn bệnh nhân của các trung tâm y khoa hàn lâm. Trừ khi được đưa vào khuôn khổ chất\nlượng một cách có chủ đích, các hoạt động giáo dục và nghiên cứu thường là những đối tác không được chú ý trong việc\ngiám sát và cải thiện chất lượng chăm sóc bệnh nhân.\n\nCác tiêu chuẩn được chia thành hai chương, vì giáo dục y khoa và nghiên cứu lâm sàng thường được tổ chức và quản lý\nriêng biệt trong các trung tâm y khoa hàn lâm. Đối với tất cả các bệnh viện đáp ứng các tiêu chí đủ điều kiện trong phần\n\"Tóm tắt các chính sách công nhận chính\" của ấn phẩm này, việc tuân thủ các yêu cầu trong hai chương này, cùng với các\nyêu cầu khác được nêu chi tiết trong sổ tay hướng dẫn lần thứ 8 này, sẽ dẫn đến việc một tổ chức được coi là được công\nnhận theo các tiêu chuẩn của Ủy ban chung quốc tế (JCI) dành cho các trung tâm y khoa hàn lâm.\n\nCác tổ chức có thắc mắc về điều kiện đủ để được công nhận là trung tâm y tế học thuật nên liên hệ với\nVăn phòng Trung tâm Công nhận JCI theo địa chỉ jciaccreditation@jcrinc.com.\n\nChương trình nghiên cứu\nđối tượng con người (HRP)\nChương trình nghiên\ncứu đối tượng con\nngười (HRP)\n\nTổng quan\nNghiên cứu đối tượng là con người được định nghĩa là nghiên cứu liên quan đến những cá nhân còn sống mà nhà\nnghiên cứu thu thập dữ liệu thông qua can thiệp hoặc tương tác với các cá nhân và/hoặc thông tin cá nhân có thể\nnhận dạng được. Loại nghiên cứu này là cam kết chính của các bệnh viện, được tích hợp với cam kết cung cấp dịch\nvụ chăm sóc an toàn, chất lượng cao. Các tiêu chuẩn HRP yêu cầu cơ quan quản lý và các nhà lãnh đạo tại các trung\ntâm y khoa học thuật có chương trình nghiên cứu tiến hành nghiên cứu đối tượng là con người phải bảo vệ tất cả\ncác đối tượng tham gia theo các nguyên tắc quốc tế và quốc gia chi phối nghiên cứu lâm sàng. Các giao thức nghiên\ncứu liên quan đến đối tượng là con người được Hội đồng Đánh giá Thể chế (IRB) hoặc cơ chế đánh giá đạo đức\nnghiên cứu khác xem xét và được giám sát liên tục khi cần thiết. Các quy trình được thiết lập để giám sát nghiên\ncứu liên quan đến nhân viên bệnh viện tiến hành nghiên cứu và tất cả các đối tượng nghiên cứu, bất kể ai hoặc tổ\nchức nào tài trợ cho nghiên cứu. Các nhà lãnh đạo bệnh viện thiết lập các chính sách và quy trình chương trình bảo\nvệ quyền của những người tham gia đối tượng là con người, xác định phạm vi chương trình, chỉ định trách nhiệm\ncủa nhà tài trợ và mô tả cách thức tiến hành quy trình đánh giá.\nCác chính sách của chương trình cũng nêu chi tiết cách thức quản lý mọi xung đột lợi ích áp dụng cho nghiên cứu\nvà bệnh viện. Những người tiến hành nghiên cứu trong tổ chức phải đáp ứng các tiêu chuẩn của bệnh viện để làm\nnhư vậy và báo cáo tất cả các sự kiện bất lợi cho hệ thống quản lý rủi ro/chất lượng của bệnh viện một cách kịp thời.\nCác nhóm dân số dễ bị tổn thương được xem xét khi cung cấp thông tin về khả năng tiếp cận nghiên cứu lâm sàng,\nđiều tra lâm sàng và thử nghiệm lâm sàng. Các bệnh viện có cơ hội tích hợp nghiên cứu vào chương trình chất lượng\nvà an toàn bệnh nhân tổng thể của mình.\n\nTiêu chuẩn\nSau đây là danh sách tất cả các tiêu chuẩn cho nghiên cứu đối tượng là con người dành cho các trung tâm y khoa học\nthuật. Các tiêu chuẩn trong chương này được trình bày ở đây để thuận tiện cho bạn mà không có các tuyên bố về mục\nđích hoặc các yếu tố có thể đo lường. Để biết thêm thông tin về các tiêu chuẩn này, vui lòng xem phần tiếp theo trong\nchương này, Tiêu chuẩn, Mục đích và","m":[],"sec":"Khả năng phục hồi của cơ sở hạ tầng và dịch vụ"},{"c":"GLD.01.00","ch":"GLD","t":"Cấu trúc, thẩm quyền và trách nhiệm của cơ quan quản lý bệnh viện được mô tả trong các điều lệ, chính sách và thủ tục hoặc các tài liệu viết tương tự.","p":"Có một thực thể quản lý—ví dụ, một nhóm cá nhân (như hội đồng quản trị hoặc hội đồng cộng đồng), một hoặc\nnhiều chủ sở hữu cá nhân được bổ nhiệm bởi cấu trúc công ty hoặc trong trường hợp của nhiều bệnh viện công,\nBộ Y tế—chịu trách nhiệm giám sát việc cung cấp dịch vụ chăm sóc, điều trị và dịch vụ của bệnh viện.\n\nMỗi bệnh viện đều có một cấu trúc lãnh đạo để hỗ trợ hoạt động và việc cung cấp dịch vụ chăm sóc, điều trị và\ndịch vụ. Tại nhiều bệnh viện, cấu trúc này được hình thành bởi nhiều nhóm lãnh đạo khác nhau và bao gồm thực\nthể quản lý, lãnh đạo điều hành và lãnh đạo phòng ban hoặc lãnh đạo cấp cao.\n\nCác nhà lãnh đạo cá nhân có thể tham gia vào nhiều nhóm và có một số vai trò riêng biệt. Nhiều trách nhiệm lãnh\nđạo ảnh hưởng trực tiếp đến việc cung cấp dịch vụ chăm sóc, điều trị và dịch vụ, cũng như hoạt động hàng ngày\ncủa bệnh viện. Do đó, điều quan trọng là phải xác định trách nhiệm của các cấp lãnh đạo khác nhau của bệnh viện.\n\nĐánh giá các nhà lãnh đạo cấp cao của bệnh viện là rất quan trọng để đảm bảo sự thống nhất về mặt chiến lược\nvà theo dõi hiệu suất của tổ chức và cá nhân. Những đánh giá này giúp CEO hiểu rõ hơn về kỳ vọng về hiệu suất\ncủa đơn vị quản lý và cung cấp phản hồi về đánh giá của đơn vị quản lý về tiến độ và sự cải thiện trong việc đạt\nđược sứ mệnh và tầm nhìn của tổ chức cũng như điều chỉnh lại chiến lược khi cần thiết.\n\nGovernance, Leadership,\ngovernanCe, leaderShIP, and dIreCtIon\n\nCơ quan quản lý bệnh viện được thể hiện hoặc hiển thị trong biểu đồ tổ chức hoặc tài liệu khác cho thấy các\nranh giới thẩm quyền và trách nhiệm. Trách nhiệm của cơ quan quản lý được mô tả trong một hoặc nhiều tài\nliệu viết. Các trách nhiệm này chủ yếu ở cấp độ phê duyệt và bao gồm những điều sau:\n•\nPhê duyệt và định kỳ xem xét sứ mệnh của bệnh viện và đảm bảo rằng công chúng biết về sứ mệnh của\nbệnh viện\n•\nPhê duyệt các kế hoạch chiến lược và hoạt động khác nhau của bệnh viện và các chính sách và quy trình\ncần thiết để vận hành bệnh viện hàng ngày\n•\nPhê duyệt sự tham gia của bệnh viện vào giáo dục chuyên môn chăm sóc sức khỏe và nghiên cứu và giám\nsát chất lượng của các chương trình đó\n•\nPhê duyệt hoặc cung cấp ngân sách vốn và hoạt động và các nguồn lực khác\n•\nBổ nhiệm và đánh giá giám đốc điều hành của bệnh viện\n\nCơ quan quản lý giám sát hiệu quả của các kế hoạch chiến lược thông qua các báo cáo định kỳ do nhóm lãnh\nđạo bệnh viện cung cấp.\n\nCác yếu tố đo lường được của GLD.01.00\n1.\nCấu trúc, thẩm quyền và trách nhiệm của cơ quan quản lý bệnh viện được mô tả trong một văn bản,\nđiều lệ và/hoặc chính sách và thủ tục, trong đó xác định những người chịu trách nhiệm quản lý bệnh\nviện.\n2.\nCơ quan quản lý phê duyệt vốn và ngân sách hoạt động của bệnh viện phù hợp với các dịch vụ của bệnh\nviện và cung cấp các nguồn lực cần thiết để đáp ứng sứ mệnh của bệnh viện.\n3.\nCơ quan quản lý phê duyệt sự tham gia của bệnh viện vào giáo dục và nghiên cứu chuyên môn chăm sóc\nsức khỏe và giám sát chất lượng của các chương trình đó.\n4.\nCơ quan quản lý bổ nhiệm và đánh giá hàng năm các giám đốc điều hành của bệnh viện vàđánh giá được\nghi lại.\n5.\nBệnh viện đã viết các chính sách mô tả thời điểm và cách thức ủy quyền của cơ quan quản lý và giám đốc điều hành.\n\nTrách nhiệm của Tổng giám đốc điều hành","m":[],"sec":"Cấu trúc lãnh đạo"},{"c":"GLD.02.00","ch":"GLD","t":"Người đứng đầu cơ quan quản lý chịu trách nhiệm điều hành bệnh viện và tuân thủ các luật và quy định hiện hành.","p":"Lãnh đạo hiệu quả là điều cần thiết để bệnh viện có thể hoạt động hiệu quả và hoàn thành sứ mệnh của\nmình. Là lãnh đạo điều hành bệnh viện cấp cao nhất do cơ quan quản lý bổ nhiệm, giám đốc điều hành\nchịu trách nhiệm cuối cùng về hoạt động chung của bệnh viện.\n\nGiám đốc điều hành hợp tác với các nhà lãnh đạo bệnh viện để xác định sứ mệnh của bệnh viện và lập kế\nhoạch cho các chính sách, quy trình và dịch vụ lâm sàng liên quan đến sứ mệnh đó. Khi được cơ quan\nquản lý chấp thuận, giám đốc điều hành chịu trách nhiệm cuối cùng trong việc thực hiện tất cả các chính\nsách và đảm bảo rằng tất cả nhân viên tuân thủ các chính sách và tất cả các luật và quy định hiện hành.\n\nGovernance, Leadership,\n\nCác yếu tố đo lường được của GLD.02.00\n1.\nTrình độ học vấn và kinh nghiệm của giám đốc điều hành phù hợp với các yêu cầu trong mô tả vị\ntrí.\n2.\nGiám đốc điều hành đề xuất các chính sách, kế hoạch chiến lược và ngân sách cho cơ quan quản\nlý.\n3.\nGiám đốc điều hành đảm bảo thực hiện nhất quán các chính sách đã được phê duyệt của bệnh\nviện.\n4.\nGiám đốc điều hành đảm bảo tuân thủ các luật và quy định hiện hành.\n5. Tổng giám đốc điều hành trả lời bất kỳ báo cáo nào từ các cơ quan thanh tra và quản lý.\n\nTrách nhiệm của người lãnh đạo","m":[],"sec":"Trách nhiệm của Tổng giám đốc điều hành"},{"c":"GLD.03.00","ch":"GLD","t":"Các nhà lãnh đạo bệnh viện được xác định và có trách nhiệm chung trong việc xác định sứ mệnh của bệnh viện và tạo ra các chương trình và chính sách cần thiết để hoàn thành sứ mệnh.","p":"Mặc dù cơ quan quản lý chỉ định giám đốc điều hành, nhưng giám đốc điều hành chịu trách nhiệm lựa\nchọn và bổ nhiệm các thành viên khác trong nhóm lãnh đạo bệnh viện, những người cùng chịu trách\nnhiệm hoàn thành sứ mệnh của tổ chức.\n\nCác nhà lãnh đạo bệnh viện có thể có chức danh chính thức, chẳng hạn như Giám đốc Y khoa hoặc\nGiám đốc Điều dưỡng; có thể là người đứng đầu các khoa hoặc dịch vụ lâm sàng hoặc phi lâm sàng;\nhoặc có thể được công nhận không chính thức về thâm niên, địa vị hoặc đóng góp của họ cho bệnh viện.\nĐiều quan trọng là các nhà lãnh đạo bệnh viện được công nhận và đưa vào quá trình xác định các giá trị\nvà sứ mệnh của bệnh viện. Các nhà lãnh đạo bệnh viện làm việc tập thể và hợp tác để phát triển các\nchương trình, chính sách và dịch vụ cần thiết để hoàn thành sứ mệnh. Khi sứ mệnh và khuôn khổ chính\nsách được chủ sở hữu hoặc các cơ quan bên ngoài bệnh viện thiết lập, các nhà lãnh đạo bệnh viện sẽ\nhợp tác để thực hiện sứ mệnh và các chính sách.\n\nCác yếu tố đo lường được của GLD.03.00\n1. Lãnh đạo bệnh viện có trách nhiệm xác định sứ mệnh, tầm nhìn và mục tiêu của bệnh viện.\n2.  Lãnh đạo bệnh viện có trách nhiệm xây dựng các chính sách và quy trình cần thiết để thực hiện sứ mệnh.\n3. Lãnh đạo bệnh viện đảm bảo các chính sách và quy trình được tuân thủ.","m":[],"sec":"Trách nhiệm của người lãnh đạo"},{"c":"GLD.03.01","ch":"GLD","t":"Lãnh đạo bệnh viện xác định, lập kế hoạch và truyền đạt loại dịch vụ lâm sàng cần thiết để đáp ứng nhu cầu của bệnh nhân được bệnh viện phục vụ.","p":"Lãnh đạo bệnh viện xác định các dịch vụ thiết yếu đáp ứng nhu cầu của nhóm bệnh nhân và phản ánh định\nhướng chiến lược của bệnh viện cũng như quan điểm của bệnh nhân được bệnh viện chăm sóc.\n\nLãnh đạo bệnh viện lập kế hoạch với các lãnh đạo khoa/dịch vụ về phạm vi và cường độ của các dịch vụ khác\nnhau do bệnh viện cung cấp trực tiếp hoặc gián tiếp. Khi áp dụng cho nhiệm vụ, lãnh đạo bệnh viện lập kế\nhoạch và tham gia với cộng đồng, bệnh viện địa phương và những bên khác để đáp ứng nhu cầu chăm sóc sức\nkhỏe cộng đồng.\n\nMột phần của kế hoạch là cung cấp các dịch vụ đồng nhất cho các nhóm bệnh nhân tương tự ở nhiều khoa.\nCác dịch vụ được hướng dẫn bởi các chính sách và quy trình dẫn đến việc cung cấp dịch vụ đồng nhất. Lãnh\nđạo khoa/dịch vụ đảm bảo rằng cùng một mức độ chăm sóc được cung cấp vào mỗi ngày trong tuần và tất cả\ncác ca làm việc đều diễn ra vào mỗi ngày.\n\nGovernance, Leadership,\ngovernanCe, leaderShIP, and dIreCtIon\nCác chính sách và thủ tục đó tuân thủ luật pháp và quy định hiện hành được phát triển tốt nhất thông qua sự\nhợp tác. Việc chăm sóc bệnh nhân thống nhất dẫn đến việc sử dụng hiệu quả các nguồn lực và cho phép đánh\ngiá kết quả của các dịch vụ chăm sóc tương tự trong toàn bệnh viện.\n\nViệc lập kế hoạch dịch vụ chăm sóc bệnh nhân liên quan đến việc các nhà lãnh đạo bệnh viện xác định cộng\nđồng và nhóm bệnh nhân của mình, xác định nhu cầu của cộng đồng đối với các dịch vụ và lập kế hoạch giao\ntiếp liên tục với các nhóm bên liên quan chính trong cộng đồng đó. Các thông tin giao tiếp có thể được truyền\nđạt trực tiếp đến cá nhân hoặc thông qua phương tiện truyền thông công cộng và thông qua các cơ quan trong\ncộng đồng hoặc bên thứ ba. Các loại thông tin được truyền đạt bao gồm thông tin về các dịch vụ, giờ hoạt động\nvà quy trình để nhận được dịch vụ chăm sóc và về chất lượng dịch vụ được cung cấp cho công chúng và các\nnguồn giới thiệu.\n\nCác yếu tố đo lường được của GLD.03.01\n1.\nLãnh đạo bệnh viện xác định và lập kế hoạch với các lãnh đạo khoa/dịch vụ về loại hình chăm sóc, điều trị\nvà dịch vụ mà bệnh viện cung cấp phù hợp với sứ mệnh của bệnh viện và nhu cầu của bệnh nhân được\nphục vụ. (Xem thêm SQE.01.05, ME 1)\n2.\nLãnh đạo bệnh viện giao tiếp với các bên liên quan chính trong cộng đồng bệnh viện để tạo điều kiện tiếp\ncận dịch vụ chăm sóc và tiếp cận thông tin về các dịch vụ chăm sóc bệnh nhân của bệnh viện. (Xem thêm\nMOI.01.00, ME 1)\n3.\nLãnh đạo bệnh viện cung cấp dữ liệu và truyền đạt thông tin liên quan đến sự an toàn và chất lượng của\ncác dịch vụ của bệnh viện cho các bên liên quan, bao gồm nhân viên điều dưỡng, nhân viên quản lý và phi\nlâm sàng, bệnh nhân, gia đình và các bên quan tâm bên ngoài.\n4.\nLãnh đạo bệnh viện thực hiện các chính sách bằng văn bản để cung cấp dịch vụ chăm sóc thống nhất theo\nnhững cách sau:\n•\nBệnh viện cung cấp dịch vụ chăm sóc và điều trị cho các nhu cầu cấp thiết của bệnh nhân và chuyển\nhọ đến mức độ chăm sóc phù hợp.\n•\nViệc tiếp cận dịch vụ chăm sóc và điều trị cấp thiết của các bác sĩ có trình độ không phụ thuộc vào\nngày trong tuần hoặc thời gian trong ngày.\n•\nMức độ nghiêm trọng của tình trạng bệnh nhân quyết định các nguồn lực được phân bổ để đáp ứng\nnhu cầu của bệnh nhân.\n•\nPhạm vi, mức độ chăm sóc, phương pháp điều trị và dịch vụ có sẵn và được cung cấp cho bệnh nhân\nlà tương đương nhau trong toàn bộ bệnh viện.","m":[],"sec":"Trách nhiệm của người lãnh đạo"},{"c":"GLD.03.02","ch":"GLD","t":"Lãnh đạo bệnh viện đảm bảo giao tiếp hiệu quả trong toàn bệnh viện.","p":"Giao tiếp hiệu quả trong bệnh viện là trách nhiệm của các nhà lãnh đạo bệnh viện. Các nhà lãnh đạo bệnh\nviện không chỉ thiết lập các thông số giao tiếp mà các nhà lãnh đạo còn đóng vai trò là hình mẫu trong việc\ngiao tiếp hiệu quả\nvề sứ mệnh, chiến lược, kế hoạch và các thông tin liên quan khác của bệnh viện. Các nhà lãnh đạo bệnh\nviện chú ý đến tính chính xác và kịp thời của thông tin được chia sẻ và truyền đạt trong toàn bệnh viện.\n\nCác nhà lãnh đạo bệnh viện hiểu được động lực giao tiếp giữa các nhóm chuyên môn; giữa các đơn vị cấu\ntrúc, chẳng hạn như các khoa; giữa các nhóm chuyên môn và không chuyên môn; giữa các bác sĩ và ban\nquản lý; giữa các bác sĩ và gia đình; và giữa các bác sĩ và các tổ chức bên ngoài.\n\nĐể phối hợp và tích hợp dịch vụ chăm sóc bệnh nhân, các nhà lãnh đạo bệnh viện xây dựng một nền văn\nhóa nhấn mạnh vào sự hợp tác và giao tiếp. Các phương pháp chính thức (ví dụ: các ủy ban thường trực,\nnhóm chung) và không chính thức (ví dụ: bản tin và áp phích) để thúc đẩy giao tiếp giữa các dịch vụ và\ntừng nhân viên được sử dụng. Việc phối hợp các dịch vụ lâm sàng xuất phát từ sự hiểu biết về sứ mệnh\nvà dịch vụ của từng khoa và sự hợp tác trong việc phát triển các chính sách và quy trình chung.\n\nGovernance, Leadership,\n\nCác yếu tố đo lường được của GLD.03.02\n1.\nLãnh đạo bệnh viện đảm bảo rằng các quy trình được triển khai để truyền đạt thông tin có\nliên quan trong toàn bệnh viện một cách kịp thời. (Xem thêm MOI.01.00, ME 1)\n2.  Lãnh đạo bệnh viện đảm bảo truyền đạt hiệu quả giữa các khoa lâm sàng và phi lâm sàng,\ncác dịch vụ và từng nhân viên. (Xem thêm MOI.01.00, ME 1)\n3. Lãnh đạo bệnh viện truyền đạt tầm nhìn, sứ mệnh, mục tiêu, chính sách và kế hoạch của bệnh\nviện tới nhân viên.\n\nLãnh đạo vì Chất lượng và An toàn Bệnh nhân","m":[],"sec":"Trách nhiệm của người lãnh đạo"},{"c":"GLD.04.00","ch":"GLD","t":"Lãnh đạo bệnh viện lập kế hoạch, phát triển và thực hiện chương trình chất lượng và an toàn cho bệnh nhân.","p":"Lãnh đạo bệnh viện có trách nhiệm thiết lập và cung cấp hỗ trợ liên tục cho cam kết của tổ chức về chất lượng.\nLãnh đạo bệnh viện xây dựng chương trình chất lượng và an toàn cho bệnh nhân để được cơ quan quản lý phê\nduyệt và thông qua tầm nhìn và sự hỗ trợ của cơ quan này, định hình văn hóa chất lượng của bệnh viện.\n\nLãnh đạo và lập kế hoạch là điều cần thiết để khởi xướng và duy trì thành công quá trình cải tiến và giảm thiểu\nrủi ro cho bệnh nhân và nhân viên. Lãnh đạo và lập kế hoạch bắt đầu từ cơ quan quản lý bệnh viện và những\nngười quản lý và lãnh đạo các hoạt động lâm sàng và quản lý hàng ngày của bệnh viện. Những cá nhân này đại\ndiện cho các nhà lãnh đạo của các khoa và dịch vụ của bệnh viện. Lãnh đạo bệnh viện lựa chọn phương pháp để\nđo lường, đánh giá và cải thiện chất lượng và an toàn cho bệnh nhân. Lãnh đạo bệnh viện cũng xác định cách\nthức chương trình sẽ được chỉ đạo và quản lý hàng ngày, chẳng hạn như thông qua một khoa chất lượng và\nđảm bảo rằng chương trình có đủ nguồn lực để có hiệu quả.\n\nLãnh đạo bệnh viện triển khai một cấu trúc và quy trình để giám sát và điều phối chung chương trình trong toàn\nbộ bệnh viện. Những hành động này đảm bảo sự phối hợp giữa tất cả các khoa và dịch vụ trong các nỗ lực đo\nlường và cải tiến. Sự phối hợp có thể đạt được thông qua hội đồng quản lý chất lượng, ủy ban, khoa hoặc cơ\ncấu khác. Sự phối hợp khuyến khích một cách tiếp cận toàn hệ thống đối với các hoạt động giám sát và cải tiến\nchất lượng trong khi giảm sự trùng lặp của nỗ lực; ví dụ, hai phòng ban độc lập đo lường các quy trình hoặc kết\nquả tương tự.\n\nViệc xác định, điều tra và phân tích cẩn thận các sự kiện an toàn bệnh nhân nghiêm trọng, cũng như các hành\nđộng khắc phục mạnh mẽ mang lại sự cải thiện hệ thống hiệu quả và bền vững, là điều cần thiết để giảm rủi ro\nvà ngăn ngừa tác hại cho bệnh nhân (xem thêm Chính sách sự kiện Sentinel tại\nhttps://www.jointcommissioninternational.org/contact-us/sentinel- event-policy/ và","m":[],"sec":"Lãnh đạo vì Chất lượng và An toàn Bệnh nhân"},{"c":"GLD.04.01","ch":"GLD","t":"Lãnh đạo bệnh viện báo cáo thông tin cải thiện chất lượng và an toàn bệnh nhân cho cơ quan quản lý và nhân viên bệnh viện.","p":"Việc truyền đạt thông tin về cải tiến chất lượng và an toàn bệnh nhân thúc đẩy việc chủ động xác định các lỗi\nhệ thống tiềm ẩn. Các nhà lãnh đạo bệnh viện phân tích và hành động đối với các vấn đề đã xảy ra, đồng thời\nkhuyến khích báo cáo các sự kiện bất lợi và các tình huống nguy cấp (“suýt xảy ra tai nạn”), cả trong nội bộ và\nbên ngoài.\n\nViệc thiết lập một chương trình an toàn tích hợp các ưu tiên về an toàn vào tất cả các quy trình, chức năng và dịch\nvụ trong bệnh viện là một phần trách nhiệm của ban lãnh đạo. Các nhà lãnh đạo bệnh viện cũng có trách nhiệm\ncung cấp các báo cáo chất lượng định kỳ để cơ quan quản lý xem xét và đảm bảo các hành động và chỉ thị của cơ\nquan quản lý liên quan đến các báo cáo về chương trình chất lượng và an toàn bệnh nhân được thực hiện.\n\nCơ quan quản lý phê duyệt chương trình chất lượng và an toàn bệnh nhân hàng năm và nhận báo cáo chất\nlượng hàng quý. Các báo cáo có thể mang tính toàn cầu hoặc tập trung vào một dịch vụ lâm sàng cụ thể, một\nnhóm bệnh nhân hoặc một số khía cạnh hoạt động. Do đó, theo thời gian, tất cả các khía cạnh của chương\ntrình chất lượng và an toàn bệnh nhân, bao gồm các sự kiện bất lợi và sự kiện cảnh báo, đều được trình lên cơ\nquan quản lý để họ cung cấp thông tin và thảo luận. Khi cuộc thảo luận dẫn đến các hành động, chẳng hạn như\nphân bổ thêm nguồn lực, những hành động đó được ghi lại trong biên bản và được xem xét lại tại các cuộc họp\ntrong tương lai.\n\nViệc có được đánh giá và hành động về các báo cáo về chương trình chất lượng và an toàn bệnh nhân từ cơ\nquan quản lý có thể là một thách thức đối với một số bệnh viện, đặc biệt là những bệnh viện là một trong\nnhiều tổ chức báo cáo với một cơ quan quản lý, chẳng hạn như Bộ Y tế (MOH). Nếu cơ quan quản lý tiếp tục\nkhông phản hồi, bệnh viện sẽ nỗ lực đáng tin cậy để liên hệ với họ. Một nỗ lực đáng tin cậy bao gồm liên hệ\nvới cơ quan quản lý nhiều lần bằng nhiều phương pháp khác nhau và ghi lại các nỗ lực/kết quả của các hoạt\nđộng truyền thông.\n\nĐiều cần thiết là các nhà lãnh đạo bệnh viện cũng phải truyền đạt thông tin về chương trình chất lượng và an\ntoàn bệnh nhân cho nhân viên. Luồng truyền thông chất lượng này thông qua các kênh hiệu quả, chẳng hạn\nnhư bản tin, bảng phân cảnh, cuộc họp nhân viên và quy trình nhân sự.\n\nGovernance, Leadership,\n\nThông tin có thể là về các dự án cải tiến mới hoặc đã hoàn thành gần đây, bao gồm:\n• Tiến độ đạt được Mục tiêu An toàn Bệnh nhân Quốc tế\n• Kết quả phân tích các sự kiện quan trọng và các sự kiện bất lợi khác\n• Nghiên cứu gần đây hoặc các chương trình chuẩn mực\n\nCác yếu tố đo lường được của GLD.04.01\n1.\nHàng năm, cơ quan quản lý sẽ xem xét và phê duyệt chương trình của bệnh viện về chất lượng và an\ntoàn cho bệnh nhân. (Xem thêm FMS.02.00, ME 4)\n2.\nÍt nhất là hàng quý, các nhà lãnh đạo bệnh viện cung cấp cho cơ quan quản lý các báo cáo bằng văn\nbản về chất lượng và an toàn cho bệnh nhân, trong đó tối thiểu phải bao gồm những nội dung sau:\n•\nTất cả các lỗi hệ thống hoặc quy trình (Xem thêm QPS.02.00, ME 3)\n•\nSố lượng và loại sự kiện giám sát (Xem thêm Chính sách sự kiện giám sát)\n•\nBệnh nhân và gia đình có được thông báo về sự kiện đó không\n•\nTất cả các hành động được thực hiện để cải thiện an toàn, cả chủ động và ứng phó với các sự cố thực tế\n•\nTheo dõi các hành động đã thực hiện, khi cần thiết\n3.\nCác nhà lãnh đạo bệnh viện thường xuyên truyền đạt thông tin về cải thiện chất lượng và chương\ntrình an toàn cho bệnh nhân cho nhân viên.","m":[],"sec":"Lãnh đạo vì Chất lượng và An toàn Bệnh nhân"},{"c":"GLD.04.02","ch":"GLD","t":"Các nhà lãnh đạo bệnh viện hợp tác để ưu tiên các quy trình toàn bệnh viện sẽ được đo lường, các hoạt động cải tiến và an toàn bệnh nhân nào sẽ được triển khai trên toàn bệnh viện và cách thức đo lường thành công của những nỗ lực toàn bệnh viện này.","p":"Do hạn chế về nhân sự và nguồn lực, không phải mọi quy trình trong bệnh viện đều có thể được đo\nlường và cải thiện cùng một lúc. Do đó, trách nhiệm chính của các nhà lãnh đạo bệnh viện là làm việc\nvới các giám đốc điều hành để ưu tiên các hoạt động đo lường và cải tiến trên toàn bệnh viện.\n\nCác nỗ lực đo lường và cải tiến tác động đến các hoạt động ở nhiều khoa và dịch vụ. Các nhà lãnh đạo\nbệnh viện tập trung vào các hoạt động đo lường và cải tiến chất lượng của bệnh viện, bao gồm đo\nlường và các hoạt động liên quan đến việc tuân thủ các Mục tiêu An toàn Bệnh nhân Quốc tế; ví dụ, đo\nlường hiệu quả của quy trình xác định bệnh nhân đối với IPSG.01.00 hoặc giám sát quy trình báo cáo\nkết quả quan trọng của các xét nghiệm chẩn đoán như đã nêu trong IPSG.02.00.\n\nCác ưu tiên có thể tập trung vào việc đạt được các mục tiêu chiến lược; ví dụ, trở thành trung tâm\nchuyển tuyến khu vực hàng đầu cho bệnh nhân ung thư. Tương tự như vậy, các nhà lãnh đạo bệnh\nviện có thể ưu tiên các dự án khác, bao gồm các dự án thực hiện các mục tiêu sau:\n• Tăng hiệu quả.\n• Giảm tỷ lệ tái nhập viện.\n• Loại bỏ các vấn đề về luồng bệnh nhân tại khoa cấp cứu.\n• Tạo quy trình giám sát chất lượng dịch vụ do các nhà thầu cung cấp.\n\nHiểu được cả tác động của việc cải thiện kết quả điều trị cho bệnh nhân và chi phí tương đối cùng\nhiệu quả của quy trình kết quả góp phần cải thiện việc thiết lập thứ tự ưu tiên trong tương lai, ở cả\ncấp độ tổ chức và cấp độ khoa/dịch vụ. Khi thông tin này được kết hợp trên toàn bệnh viện, các nhà\nlãnh đạo bệnh viện có thể hiểu rõ hơn cách phân bổ các nguồn lực về chất lượng và an toàn cho bệnh\nnhân.\n\nCác nhà lãnh đạo bệnh viện cùng nhau làm việc để xem xét các ưu tiên ở cấp độ hệ thống nhằm lan tỏa\ntác động của các cải tiến trên diện rộng khắp bệnh viện; ví dụ, cải thiện hệ thống quản lý thuốc của\nbệnh viện. Quy trình thiết lập thứ tự ưu tiên bao gồm việc xem xét dữ liệu có sẵn về hệ thống và quy\ntrình nào thể hiện sự khác biệt lớn nhất trong quá trình triển khai và kết quả.\n\nGovernance, Leadership,\ngovernanCe, leaderShIP, and dIreCtIon\nSử dụng dữ liệu có sẵn, các nhà lãnh đạo bệnh viện đánh giá tác động của những cải tiến trên toàn bệnh viện. Đo lường\nsự cải thiện về hiệu quả của một quy trình lâm sàng phức tạp và/hoặc xác định mức giảm chi phí và sử dụng tài nguyên\nsau khi cải tiến quy trình là những ví dụ. Đo lường tác động của một cải tiến hỗ trợ việc hiểu được chi phí tương đối\nđể đầu tư vào chất lượng và lợi nhuận về con người, tài chính và các lợi nhuận khác từ khoản đầu tư đó. Các nhà lãnh\nđạo bệnh viện ủng hộ việc tạo ra các công cụ đơn giản để định lượng việc sử dụng tài nguyên của quy trình cũ và để\nđánh giá quy trình mới.\n\nViệc thu thập và phân tích dữ liệu về lỗi chẩn đoán cũng rất quan trọng và các nhà lãnh đạo bệnh viện nên đưa dữ liệu\nnày vào quá trình ra quyết định dựa trên dữ liệu của mình. Theo Hiệp hội Cải thiện Chẩn đoán trong Y học, lỗi chẩn\nđoán là những chẩn đoán bị bỏ sót, sai hoặc chậm trễ, được phát hiện bằng các kết quả xét nghiệm xác định sau đó. Một\nnghiên cứu (Harvard) phát hiện ra rằng lỗi chẩn đoán chiếm 17% các lỗi có thể phòng ngừa ở bệnh nhân. Một nghiên\ncứu khác (Johns Hopkins) phát hiện ra rằng các lỗi chẩn đoán phổ biến nhất liên quan đến các biến cố mạch máu, ung\nthư và nhiễm trùng. Đây cũng là những nguyên nhân lớn nhất gây ra các khiếu nại về hành nghề y sai trái.\n\nNguyên nhân gây ra lỗi chẩn đoán rất phức tạp và hiếm khi là lỗi của một bác sĩ lâm sàng hoặc nhân viên nào đó. Các\nyếu tố dẫn đến lỗi chẩn đoán bao gồm sự phức tạp trong chẩn đoán, sự cố trong giao tiếp hoặc phối hợp chăm sóc, mất\nkết quả xét nghiệm, trục trặc thiết bị, sự sẵn có của các bác sĩ lâm sàng chuyên khoa và lỗi nhận thức hoặc thiên vị. Giao\ntiếp vòng kín là một phương pháp thiết yếu để giảm lỗi chẩn đoán và điều này có nghĩa là mọi kết quả xét nghiệm luôn\nđược gửi, nhận, xác nhận và xử lý.\n\nThông thường, việc theo dõi các hành động đã thực hiện là một bước cần thiết và thậm chí có thể rất quan trọng đối\nvới việc chăm sóc bệnh nhân. Điều này đòi hỏi sự phối hợp chăm sóc trong suốt quá trình liên tục để chuyển giao kết\nquả xét nghiệm, giải thích kết quả và truyền đạt chúng bằng ngôn ngữ mà bệnh nhân có thể hiểu được. Việc triển khai\nquy trình giao tiếp vòng kín đòi hỏi\nmột số biện pháp can thiệp, chẳng hạn như thiết kế lại quy trình giao tiếp, cải thiện sự tham gia của bệnh nhân, thiết\nlập các biện pháp dựa trên dữ liệu để theo dõi và hành động liên tục trong quá trình giao tiếp kết quả chẩn đoán và đánh\ngiá kết quả của bệnh nhân.\n\nCác yếu tố đo lường được của GLD.04.02\n1.\nLãnh đạo bệnh viện sử dụng dữ liệu có sẵn để thiết lập các ưu tiên chung cho các hoạt động đo\nlường và cải tiến trên toàn bệnh viện và xem xét các cải tiến hệ thống tiềm năng. (Xem thêm\nQPS.04.00, ME 1)\n2.\nLãnh đạo bệnh viện thiết lập các ưu tiên để tuân thủ các Mục tiêu An toàn Bệnh nhân Quốc tế.\n3.\nLãnh đạo bệnh viện tiến hành đánh giá dữ liệu tập trung vào rủi ro, dựa trên dữ liệu hàng năm để\nphát hiện các lỗi chẩn đoán tập trung vào ít nhất một trong các lĩnh vực sau:\n• X quang\n• Bệnh học\n• Xét nghiệm/vi sinh\n• Phối hợp chăm sóc\n4.\nLãnh đạo bệnh viện triển khai các biện pháp can thiệp dựa trên bằng chứng dựa trên đánh giá rủi\nro lỗi chẩn đoán và phân tích dữ liệu với mục đích cải thiện các lĩnh vực chẩn đoán trọng tâm và\nđánh giá hiệu quả của các biện pháp can thiệp một cách liên tục, đánh giá lại khi cần thiết.\n\nLãnh đạo về Hợp đồng và Tài nguyên","m":[],"sec":"Lãnh đạo vì Chất lượng và An toàn Bệnh nhân"},{"c":"GLD.05.00","ch":"GLD","t":"Lãnh đạo bệnh viện chịu trách nhiệm xem xét, lựa chọn và giám sát các hợp đồng lâm sàng và phi lâm sàng và kiểm tra việc tuân thủ các dịch vụ theo hợp đồng khi cần thiết.","p":"Đánh giá tất cả các dịch vụ được cung cấp thông qua các dịch vụ theo hợp đồng đều tác động đến chất lượng và sự\nan toàn của việc chăm sóc bệnh nhân. Để cung cấp và duy trì tính liên tục của các dịch vụ cho bệnh nhân, các nhà\nlãnh đạo bệnh viện mô tả và giám sát phạm vi các dịch vụ được cung cấp thông qua các thỏa thuận hợp đồng.\n\nCác quy trình chăm sóc bệnh nhân tại bệnh viện được hỗ trợ bởi một loạt các hoạt động vận hành bao gồm phân\nphối vật tư và dịch vụ trên toàn bộ tổ chức. Hậu cần chăm sóc sức khỏe bao gồm quy trình xử lý các dịch vụ (ví dụ:\ndịch vụ chụp X-quang và chẩn đoán hình ảnh, dịch vụ kế toán tài chính, dọn dẹp, thực phẩm, khăn trải giường) và\nhàng hóa vật chất (ví dụ: dược phẩm, sản phẩm y tế phẫu thuật, thiết bị y tế, vật dụng vô trùng, khăn trải giường,\nthực phẩm). Bệnh viện thường có tùy chọn cung cấp trực tiếp các dịch vụ lâm sàng và quản lý hoặc sắp xếp các dịch\nvụ đó thông qua giới thiệu, tư vấn, sắp xếp hợp đồng hoặc các thỏa thuận khác.\n\nĐại dịch COVID-19 đã nêu bật nhu cầu tăng cường năng lực của các bệnh viện để ứng phó và duy trì khả năng tiếp\ncận các dịch vụ chăm sóc sức khỏe thiết yếu. Tổ chức Y tế Thế giới xác định hợp đồng là một công cụ quan trọng để\ntăng năng lực và duy trì các nguồn lực quan trọng cho việc chăm sóc bệnh nhân. Việc xem xét và giám sát các hợp\nđồng cũng cho phép bệnh viện chuẩn bị cho tính liên tục của các dịch vụ trong trường hợp khẩn cấp.\nHướng dẫn của Tổ chức Y tế Thế giới về dịch vụ ký hợp đồng khuyến nghị rằng các nhà lãnh đạo bệnh viện nên\nthực hiện những điều sau:\n• Xác định mục đích và cấu trúc của hợp đồng.\n• Lên kế hoạch cho quy trình mua sắm.\n• Mua sắm và ký hợp đồng.\n• Theo dõi mối quan hệ hợp đồng.\n\nBệnh viện cần tiếp nhận, phân tích và hành động dựa trên thông tin chất lượng và dữ liệu hiệu suất từ các nguồn\nbên ngoài. Hợp đồng với nguồn dịch vụ bên ngoài bao gồm kỳ vọng về chất lượng và an toàn cho bệnh nhân cũng\nnhư dữ liệu sẽ được cung cấp cho bệnh viện, tần suất và định dạng của chúng. Các nhà lãnh đạo khoa/dịch vụ tiếp\nnhận và hành động dựa trên các báo cáo chất lượng từ các cơ quan ký hợp đồng liên quan đến phạm vi dịch vụ\nđược cung cấp trong khoa/dịch vụ của họ và đảm bảo rằng các báo cáo được tích hợp vào quy trình đo lường chất\nlượng của bệnh viện.\n\nCác nhà lãnh đạo bệnh viện chịu trách nhiệm về các hợp đồng đó hoặc các thỏa thuận khác để đảm bảo rằng các\ndịch vụ đáp ứng được nhu cầu của bệnh nhân và được đưa vào như một phần của các hoạt động cải tiến và quản lý\nchất lượng của bệnh viện. Các nhà lãnh đạo khoa/dịch vụ tham gia vào việc xem xét và lựa chọn tất cả các hợp đồng\nlâm sàng và phi lâm sàng và chịu trách nhiệm giám sát các hợp đồng đó.\n\nCác yếu tố đo lường được của GLD.05.00\n1.\nLãnh đạo bệnh viện xác định một hoặc nhiều cá nhân có trách nhiệm giám sát các hợp đồng để đáp\nứng nhu cầu của bệnh nhân và ban quản lý. (Xem thêm AOP.03.00, ME 3)\n2.\nBệnh viện có mô tả bằng văn bản về bản chất và phạm vi của các dịch vụ được cung cấp thông qua\ncác thỏa thuận hợp đồng.\n3.\nLãnh đạo khoa/dịch vụ tham gia vào việc xem xét, lựa chọn và giám sát các hợp đồng lâm sàng và phi\nlâm sàng. (Xem thêm ASC.01.00, ME 6)\n4.\nLãnh đạo bệnh viện giám sát việc tuân thủ các dịch vụ theo hợp đồng và thực hiện các hành động\nđể duy trì tính liên tục của các dịch vụ khi hợp đồng được đàm phán lại hoặc chấm dứt. (Xem thêm\nAOP.03.09, ME 3 và 4; AOP.05.06, ME 3 và 4)\n5.\nTất cả các hợp đồng đều quy định dữ liệu về chất lượng và hiệu suất phải báo cáo cho bệnh viện,\ntần suất và cơ chế báo cáo, cũng như cách bệnh viện sẽ phản hồi khi các yêu cầu hoặc kỳ vọng về\nchất lượng không được đáp ứng. (Xem thêm AOP.03.09, MEs 3 và 4; AOP.05.06, MEs 3 và 4)\n6.\nDữ liệu chất lượng được báo cáo theo hợp đồng được tích hợp vào chương trình giám sát chất\nlượng của bệnh viện.\n\nGovernance, Leadership,\ngovernanCe, leaderShIP, and dIreCtIon","m":[],"sec":"Lãnh đạo về Hợp đồng và Tài nguyên"},{"c":"GLD.05.01","ch":"GLD","t":"Lãnh đạo bệnh viện đảm bảo rằng các bác sĩ chăm sóc sức khỏe và nhân viên lâm sàng không làm việc tại bệnh viện có đủ trình độ và có năng lực và/hoặc được hưởng đặc quyền đối với các dịch vụ cung cấp cho bệnh nhân của bệnh viện.","p":"Lãnh đạo bệnh viện có trách nhiệm xác nhận rằng các bác sĩ chăm sóc sức khỏe và nhân viên lâm sàng có đủ\nnăng lực và/hoặc đặc quyền cung cấp dịch vụ cho bệnh nhân của họ.\nHợp đồng với các bác sĩ chăm sóc sức khỏe độc lập và các nhân viên lâm sàng khác có thể bao gồm các dịch\nvụ phòng ngừa, chữa bệnh, phục hồi, phẫu thuật, phục hồi chức năng hoặc các dịch vụ y tế hoặc nha khoa\nkhác cho bệnh nhân; hoặc các dịch vụ giải thích\ncho bệnh nhân, chẳng hạn như bệnh lý, X quang hoặc dịch vụ xét nghiệm. Các dịch vụ do các bác sĩ chăm\nsóc sức khỏe độc lập cung cấp cũng có thể bao gồm dịch vụ chăm sóc sức khỏe từ xa hoặc dịch vụ X quang\ntừ xa. Trong một số trường hợp, những cá nhân này có thể ở bên ngoài khu vực hoặc quốc gia của bệnh\nviện. Các hợp đồng quy định rằng nhân viên lâm sàng được cung cấp phải đáp ứng nhu cầu của bệnh nhân\nvà yêu cầu của bệnh viện đối với nhân viên tương tự.\n\nCác bác sĩ chăm sóc sức khỏe độc lập có thể đi cùng với nhân viên báo cáo với họ và không phải là một phần\ncủa bệnh viện (ví dụ: trợ lý phẫu thuật đi cùng bác sĩ phẫu thuật). Bất kỳ nhân viên hỗ trợ nào đi cùng các\nbác sĩ chăm sóc sức khỏe độc lập và cung cấp dịch vụ chăm sóc và dịch vụ trong bệnh viện đều tuân thủ các\nyêu cầu về xác minh nguồn chính.\nCác yếu tố đo lường được của GLD.05.01\n1.\nTất cả các dịch vụ chẩn đoán, tư vấn và điều trị do các bác sĩ chăm sóc sức khỏe độc lập bên\nngoài bệnh viện cung cấp đều được bệnh viện cấp chứng chỉ và có đặc quyền để cung cấp\ncác dịch vụ đó.\n2.\nCác bác sĩ chăm sóc sức khỏe độc lập cung cấp dịch vụ chăm sóc bệnh nhân tại cơ sở của\nbệnh viện nhưng không phải là nhân viên hoặc thành viên của đội ngũ nhân viên lâm sàng\nđều được cấp chứng chỉ, có đặc quyền và được đánh giá theo yêu cầu trong SQE.05.00 đến\nSQE.07.01.\n3.\nBất kỳ nhân viên hỗ trợ nào đi cùng các bác sĩ chăm sóc sức khỏe độc lập và cung cấp dịch\nvụ chăm sóc trong bệnh viện đều tuân thủ các yêu cầu về xác minh nguồn chính.\n4.\nChất lượng dịch vụ của các bác sĩ độc lập bên ngoài bệnh viện được giám sát như một thành\nphần của chương trình cải tiến chất lượng của bệnh viện.","m":[],"sec":"Lãnh đạo về Hợp đồng và Tài nguyên"},{"c":"GLD.05.02","ch":"GLD","t":"Các nhà lãnh đạo bệnh viện sử dụng dữ liệu và thông tin trong việc ra quyết định về nguồn lực để hiểu được ý nghĩa của nó đối với sự an toàn và chất lượng của bệnh nhân.","p":"Lãnh đạo bệnh viện sử dụng dữ liệu và thông tin để hướng dẫn phù hợp cho các quyết định của họ liên quan\nđến việc mua và sử dụng nguồn nhân lực và kỹ thuật để hiểu rõ hơn tác động của nó đối với hoạt động chung\ncủa bệnh viện.\n\nLãnh đạo bệnh viện cải thiện việc ra quyết định khi họ có dữ liệu, thông tin và công cụ để hỗ trợ các quyết\nđịnh. Ví dụ, khi bệnh viện cần thay thế hoặc bổ sung máy bơm truyền dịch: Thông tin về yêu cầu bảo trì, yêu\ncầu đào tạo hoặc đào tạo lại nhân viên, thông tin về tỷ lệ hỏng hóc trước đây và các sự cố an toàn cho bệnh\nnhân, sở thích của nhân viên và các vấn đề báo động sẽ dẫn đến các quyết định dựa nhiều hơn vào chất lượng\nvà sự an toàn của bệnh nhân hơn là chỉ dựa trên chi phí. Tương tự như vậy, khi đưa ra quyết định liên quan\nđến việc cắt giảm hoặc điều chuyển nhân viên điều dưỡng, cần cân nhắc đến các tác động đối với chất lượng\nchăm sóc bệnh nhân và sự an toàn của bệnh nhân để thông báo cho quyết định. Đại dịch COVID-19 đặt ra\nnhững yêu cầu chưa từng có đối với toàn bộ hệ thống y tế và đẩy chúng vào tình trạng quá tải. Các bệnh viện\nphải đối mặt với vấn đề khó khăn là đảm bảo đủ nhân sự và nguồn lực cho một số lượng lớn bệnh nhân nguy\nkịch.\n\nGovernance, Leadership,\n\nCác bệnh viện sẽ được chuẩn bị tốt hơn khi các nhà lãnh đạo xây dựng một quy trình để thu thập dữ\nliệu và thông tin cho các quyết định về nguồn lực nhằm đảm bảo an toàn cho bệnh nhân và chất\nlượng chăm sóc\n\nMột thành phần của việc thu thập dữ liệu liên quan đến các quyết định về nguồn lực là hiểu được yêu cầu\nhoặc khuyến nghị về nhân sự, thiết bị y tế, vật tư và thuốc men cần thiết để liên tục cung cấp dịch vụ. Các\nkhuyến nghị về thiết bị y tế, vật tư và thuốc men có thể đến từ một cơ quan chính phủ, các tổ chức chuyên\nnghiệp quốc gia hoặc quốc tế hoặc các nguồn có thẩm quyền khác. Việc thu thập ý kiến đóng góp từ các bác\nsĩ lâm sàng, kỹ sư lâm sàng và nhân viên tuyến đầu cũng rất quan trọng. Khi các quyết định về nguồn lực\nđược đưa ra bởi bên thứ ba—ví dụ: Bộ Y tế—các nhà lãnh đạo bệnh viện cung cấp dữ liệu và thông tin cho\nbên thứ ba về kinh nghiệm và sở thích của họ để đưa ra thông tin tốt hơn cho các lựa chọn về nguồn lực\ntrong tương lai.\n\nCác yếu tố đo lường được của GLD.05.02\n1.\nLãnh đạo bệnh viện sử dụng dữ liệu và thông tin khi đưa ra quyết định mua, thay thế hoặc loại\nbỏ thiết bị y tế. (Xem thêm FMS.07.00, ME 1)\n2.\nLãnh đạo bệnh viện sử dụng dữ liệu và thông tin khi đưa ra quyết định về nhu cầu nhân sự để\nliên tục hỗ trợ an toàn và chất lượng bệnh nhân.\n3.\nLãnh đạo bệnh viện sử dụng các khuyến nghị của các tổ chức chuyên nghiệp và các nguồn có\nthẩm quyền khác khi đưa ra quyết định về nguồn lực. (Xem thêm GHI.04.00, ME 1 và 2)\n4.\nCác nhà lãnh đạo bệnh viện theo dõi kết quả quyết định của họ và sử dụng dữ liệu để đánh giá và\ncải thiện chất lượng quyết định mua và phân bổ nguồn lực của họ.","m":[],"sec":"Lãnh đạo về Hợp đồng và Tài nguyên"},{"c":"GLD.05.03","ch":"GLD","t":"Các nhà lãnh đạo bệnh viện thiết lập chiến lược chuỗi cung ứng bao gồm bảo vệ bệnh nhân và nhân viên khỏi nguồn cung không ổn định, bị ô nhiễm, lỗi và giả mạo.","p":"Bệnh viện cần nhiều loại mặt hàng khác nhau và vấn đề lưu trữ và phân phối những mặt hàng này trong toàn\nbệnh viện rất quan trọng để cung cấp dịch vụ chăm sóc bệnh nhân chất lượng cao. Các nhà lãnh đạo bệnh\nviện cần hiểu rõ luồng hàng hóa để liên tục cung cấp dịch vụ chăm sóc bệnh nhân an toàn và chất lượng cao.\n\nQuản lý chuỗi cung ứng là chìa khóa để đảm bảo an toàn và chất lượng hàng hóa của bệnh viện. Chuỗi cung\nứng bao gồm các bước từ khâu sản xuất đến khâu giao hàng đến bệnh viện. Do hạn chế về nhân sự và nguồn\nlực, không phải mọi chuỗi cung ứng đều có thể được theo dõi và đánh giá cùng một lúc. Do đó, bệnh viện\nxác định những mặt hàng quan trọng nhất và có rủi ro cao nhất ảnh hưởng đến dịch vụ chăm sóc bệnh nhân\ntrên toàn bệnh viện. Những mặt hàng quan trọng nhất và có rủi ro cao nhất này khác nhau ở mỗi tổ chức tùy\nthuộc vào phạm vi dịch vụ, bối cảnh và luật pháp\nvà quy định của bệnh viện. Là một phần của chiến lược chuỗi cung ứng, các nhà lãnh đạo bệnh viện xác định\nnhững mặt hàng có rủi ro cao nhất và phác thảo các bước giảm thiểu để đảm bảo tính liên tục của dịch vụ.\n\nChiến lược chuỗi cung ứng không chỉ là đánh giá triển vọng về những mặt hàng có rủi ro cao mà còn bao\ngồm việc truy vết những mặt hàng sau khi chúng đã vào bệnh viện. Bệnh viện có quy trình xác định thuốc\nmen, vật tư y tế và thiết bị y tế không ổn định, bị nhiễm bẩn, lỗi hoặc hàng giả và truy xuất ngược lại bệnh\nviện để xác định nguồn gốc hoặc nguyên nhân của vấn đề, nếu có thể. Khi áp dụng, bệnh viện sẽ thông báo\ncho nhà sản xuất và/hoặc nhà phân phối khi vật tư không ổn định, bị nhiễm bẩn, lỗi\nhoặc hàng giả được xác định thông qua truy xuất hồi cứu. Chiến lược chuỗi cung ứng phải nêu rõ các\nkhuyến nghị sẽ đảm bảo tính liên tục của các dịch vụ chăm sóc bệnh nhân an toàn và chất lượng cao. Ví dụ,\nchiến lược chuỗi cung ứng khuyến nghị rằng bệnh viện không chỉ duy trì hàng tồn kho khẩu trang và chất\nkhử trùng mà còn bao gồm hai nhà cung cấp dự phòng có thể cung cấp các vật tư quan trọng này trong\ntrường hợp COVID-19 bùng phát trở lại.\n\nGovernance, Leadership,\ngovernanCe, leaderShIP, and dIreCtIon\nKhi vật tư bệnh viện được mua, lưu trữ và phân phối bởi một cơ quan chính phủ, bệnh viện tham gia vào\ncác chương trình để phát hiện và báo cáo các vật tư nghi ngờ không ổn định, bị ô nhiễm, lỗi và giả mạo và\nthực hiện các biện pháp để ngăn ngừa nguy cơ gây hại cho bệnh nhân. Mặc dù một bệnh viện công có thể\nkhông biết tính toàn vẹn của từng nhà cung cấp trong chuỗi, nhưng bệnh viện có thể biết được cách thức\nmua và quản lý vật tư của cơ quan chính phủ hoặc phi chính phủ.\n\nCác yếu tố đo lường được của GLD.05.03\n1.\nLãnh đạo bệnh viện thiết lập chiến lược chuỗi cung ứng bằng văn bản thực hiện các nội dung sau:\n•\nXác định các bước trong chuỗi cung ứng.\n•\nXác định rủi ro trong các bước của chuỗi cung ứng.\n•\nXác định nguồn cung có rủi ro cao nhất.\n•\nPhác thảo các khuyến nghị về việc giảm thiểu rủi ro sẽ đảm bảo tính liên tục của các dịch vụ chăm sóc\nbệnh nhân an toàn và chất lượng cao.\n2.\nBệnh viện có quy trình thực hiện truy xuất ngược lại các vật tư được phát hiện không ổn định, bị nhiễm bẩn, lỗi\nhoặc giả mạo.\n3.\nBệnh viện thông báo cho nhà sản xuất và/hoặc nhà phân phối khi phát hiện vật tư không ổn định, bị nhiễm bẩn, lỗi\nhoặc giả mạo.\n\nChỉ đạo các khoa và dịch vụ của bệnh viện","m":[],"sec":"Lãnh đạo về Hợp đồng và Tài nguyên"},{"c":"GLD.06.00","ch":"GLD","t":"Bệnh viện xác định phạm vi dịch vụ và cơ cấu của từng khoa hoặc dịch vụ.","p":"Chăm sóc lâm sàng, kết quả điều trị cho bệnh nhân và quản lý chung của bệnh viện chỉ tốt khi các hoạt động lâm\nsàng, quản lý và vận hành của từng khoa hoặc dịch vụ riêng lẻ. Hiệu suất tốt của khoa hoặc dịch vụ đòi hỏi sự lãnh\nđạo rõ ràng từ những cá nhân có trình độ.\n\nLãnh đạo bệnh viện chịu trách nhiệm phối hợp chăm sóc, điều trị và dịch vụ giữa các chương trình, dịch vụ, cơ sở\nhoặc khoa khác nhau của bệnh viện. Trong các khoa hoặc dịch vụ lớn hơn, có thể có nhiều lãnh đạo. Trách nhiệm\ncủa từng vai trò được xác định bằng văn bản.\n\nMỗi lãnh đạo khoa/dịch vụ báo cáo nhu cầu về nguồn lực của họ cho lãnh đạo bệnh viện. Điều này giúp đảm bảo\nluôn có đủ nhân viên, không gian, thiết bị y tế, công nghệ và các nguồn lực khác để đáp ứng nhu cầu của bệnh nhân.\n\nLãnh đạo khoa/dịch vụ xem xét các dịch vụ do khoa hoặc dịch vụ cung cấp và lập kế hoạch cũng như trình độ học\nvấn, kỹ năng, kiến thức và kinh nghiệm cần thiết của đội ngũ nhân viên chuyên môn của khoa để cung cấp các dịch\nvụ đó. Lãnh đạo khoa/dịch vụ xây dựng các tiêu chí phản ánh sự cân nhắc này và sau đó lựa chọn nhân viên.\n\nLãnh đạo khoa/dịch vụ cũng có thể làm việc với bộ phận nhân sự hoặc các bộ phận khác trong quá trình tuyển chọn\ndựa trên các khuyến nghị của họ.\n\nCác nhà lãnh đạo khoa/dịch vụ đảm bảo rằng tất cả nhân viên trong khoa hoặc dịch vụ hiểu rõ trách nhiệm của mình\nvà thiết lập định hướng và đào tạo cho nhân viên mới. Định hướng bao gồm sứ mệnh của bệnh viện, sứ mệnh của\nkhoa hoặc dịch vụ, phạm vi dịch vụ được cung cấp và các chính sách và thủ tục liên quan đến việc cung cấp dịch vụ.\nVí dụ, tất cả nhân viên đều hiểu các thủ tục phòng ngừa và kiểm soát nhiễm trùng trong bệnh viện và trong khoa\nhoặc dịch vụ. Khi các chính sách hoặc thủ tục mới hoặc được sửa đổi được triển khai, nhân viên sẽ được đào tạo.\n\nCác dịch vụ lâm sàng cung cấp cho bệnh nhân được phối hợp và tích hợp trong từng khoa hoặc dịch vụ.\nNgoài ra, mỗi khoa hoặc dịch vụ phối hợp và tích hợp các dịch vụ của mình với các khoa và dịch vụ khác.\nViệc trùng lặp các dịch vụ không cần thiết được tránh hoặc loại bỏ để tiết kiệm tài nguyên. Mặc dù các\nnhà lãnh đạo khoa/dịch vụ đưa ra các khuyến nghị liên quan đến nhu cầu về con người và các nguồn lực\nkhác, nhưng những nhu cầu đó đôi khi thay đổi hoặc không được đáp ứng đầy đủ.\n\nGovernance, Leadership,\n\nDo đó, các nhà lãnh đạo khoa/dịch vụ có một quy trình để ứng phó với tình trạng thiếu hụt nguồn lực\nnhằm đảm bảo chăm sóc an toàn và hiệu quả cho tất cả bệnh nhân.\n\nMỗi trưởng khoa/trưởng phòng dịch vụ xác định, bằng văn bản, các dịch vụ do khoa cung cấp và tích hợp\nhoặc phối hợp các dịch vụ đó với các dịch vụ của các khoa khác. Các trưởng khoa/trưởng phòng dịch vụ\nhợp tác để xác định định dạng và nội dung thống nhất của các tài liệu lập kế hoạch cụ thể của khoa. Nhìn\nchung, các tài liệu do mỗi khoa lâm sàng lập ra sẽ xác định mục tiêu của khoa, cũng như xác định các dịch\nvụ hiện tại và đã lập kế hoạch.\n\nCác chính sách và quy trình của khoa phản ánh các mục tiêu và dịch vụ của khoa cũng như kiến thức, kỹ\nnăng và sự sẵn có của đội ngũ nhân viên cần thiết để đánh giá và đáp ứng nhu cầu chăm sóc bệnh nhân.\n\nCác yếu tố đo lường được của GLD.06.00\n1.\nMỗi khoa hoặc dịch vụ trong bệnh viện được chỉ đạo bởi một cá nhân có trình độ, đào tạo, giáo\ndục và kinh nghiệm tương đương với các dịch vụ được cung cấp. (Xem thêm AOP.03.01, ME 1;\nAOP.04.00, ME 1; AOP.05.01, ME 1; MMU.01.00, ME 1 và 5; FMS.01.01, ME 1; HCT.01.00,\nME 2; PCI.01.00, ME 1; QPS.01.00, ME 1; GHI.01.00, ME 3)\n2.\nCác nhà lãnh đạo khoa/dịch vụ đề xuất không gian, thiết bị y tế, nhân sự, công nghệ và các nguồn\nlực khác mà khoa hoặc dịch vụ cần và có quy trình để ứng phó với tình trạng thiếu hụt. (Xem\nthêm SQE.01.00, ME 1)\n3.\nCác tài liệu của khoa hoặc dịch vụ mô tả các dịch vụ hiện tại và đã lên kế hoạch do từng khoa\nhoặc dịch vụ cung cấp. (Xem thêm ACC.02.02, ME 3)\n4.\nCó sự phối hợp và/hoặc tích hợp các dịch vụ trong và giữa các phòng ban và dịch vụ khác. (Xem\nthêm ACC.02.02, ME 4; ACC.03.00, ME 1; ACC.05.00, ME 1)","m":[],"sec":"Chỉ đạo các khoa và dịch vụ của bệnh viện"},{"c":"GLD.06.01","ch":"GLD","t":"Các nhà lãnh đạo khoa/dịch vụ tham gia vào các ưu tiên cải tiến trên toàn bệnh viện và trong việc theo dõi và cải thiện việc chăm sóc bệnh nhân cụ thể cho khoa/dịch vụ.","p":"Mỗi khoa đều tham gia vào các hoạt động cải tiến phản ánh và đóng góp vào các ưu tiên của toàn bệnh\nviện nhằm thiết lập một chương trình chất lượng và an toàn cho bệnh nhân tích hợp.\n\nCác nhà lãnh đạo khoa có trách nhiệm đảm bảo chất lượng chăm sóc và dịch vụ do khoa/dịch vụ của\nmình cung cấp. Các nhà lãnh đạo khoa/dịch vụ xác định các ưu tiên cải tiến giải quyết các hoạt động lâm\nsàng hoặc phi lâm sàng cụ thể cho khoa hoặc dịch vụ. Ví dụ, một khoa hoặc dịch vụ lâm sàng sẽ tham gia\nvào nỗ lực toàn bệnh viện nhằm cải thiện thông tin liên lạc bàn giao và có thể giám sát và giảm sự thay\nđổi trong quy trình nội bộ như việc chỉ định xét nghiệm chẩn đoán cho những bệnh nhân mắc cùng một\ntình trạng. Tương tự như vậy, một khoa quản lý có thể tham gia vào các dự án tự động hóa để cải thiện\nthông tin liên lạc bàn giao và có thể giám sát và cải thiện độ chính xác của hóa đơn bệnh nhân.\n\nCác hoạt động đo lường chất lượng có thể quan trọng để đảm bảo rằng nhà lãnh đạo khoa/dịch vụ có\nthông tin khách quan để hỗ trợ các hoạt động cải tiến. Theo thời gian, đo lường chất lượng bao gồm tất\ncả các dịch vụ do khoa hoặc dịch vụ cung cấp và bao gồm các đặc quyền lâm sàng của tất cả các bác sĩ.\nTrong một số\ntrường hợp, các biện pháp sẽ được liên kết với các hướng dẫn thực hành lâm sàng, lộ trình lâm sàng và\ncác giao thức lâm sàng được triển khai trong khoa hoặc dịch vụ. Dữ liệu cần thiết để hỗ trợ việc đánh giá\ncác y tá và các chuyên gia chăm sóc sức khỏe khác trong khoa. Mặc dù những cá nhân này có mô tả công\nviệc thay vì các đặc quyền lâm sàng, nhưng người đứng đầu khoa/dịch vụ vẫn chịu trách nhiệm đánh giá\ncông việc của họ. Trong nhiều trường hợp, các hướng dẫn thực hành lâm sàng được triển khai trong\nkhoa hoặc dịch vụ sẽ có các lộ trình và giao thức liên quan hỗ trợ việc thu thập dữ liệu đo lường cho\nnhân viên điều dưỡng và các chuyên gia chăm sóc sức khỏe khác.\n\nGovernance, Leadership,\ngovernanCe, leaderShIP, and dIreCtIon\nLãnh đạo khoa hoặc dịch vụ thực hiện việc lựa chọn và giám sát các biện pháp hoặc chỉ số cụ thể cho\nkhoa hoặc dịch vụ bao gồm các nội dung sau:\n• Các ưu tiên đo lường và cải tiến trên toàn bệnh viện do lãnh đạo bệnh viện đặt ra liên quan đến khoa\nhoặc dịch vụ cụ thể của họ\n• Các biện pháp liên quan đến các ưu tiên của khoa/dịch vụ cụ thể để giảm sự thay đổi, cải thiện tính an\ntoàn của các thủ thuật/phương pháp điều trị có nguy cơ cao, cải thiện sự hài lòng của bệnh nhân hoặc cải\nthiện hiệu quả\n\nViệc lựa chọn các biện pháp phải dựa trên các hoạt động và quy trình cần cải thiện trong khoa hoặc dịch\nvụ. Đối với mỗi biện pháp, cần đặt ra một mục tiêu. Dự kiến rằng phép đo ban đầu sẽ không đạt được\nmục tiêu; tuy nhiên, khi các chiến lược cải tiến được triển khai, lãnh đạo khoa/dịch vụ nên mong đợi\nthấy sự cải thiện hướng tới mục tiêu. Khi mục tiêu đã đạt được và duy trì trong ít nhất bốn giai đoạn đo\nlường, một biện pháp mới sẽ được lựa chọn.\n\nLãnh đạo khoa hoặc dịch vụ lâm sàng có trách nhiệm đảm bảo rằng các hoạt động đo lường tạo cơ hội để\nđánh giá nhân viên cũng như các quy trình chăm sóc. Do đó, theo thời gian, phép đo bao gồm tất cả các\ndịch vụ được cung cấp. Dữ liệu và thông tin thu được rất quan trọng đối với nỗ lực cải thiện của khoa\nhoặc dịch vụ nhưng cũng quan trọng đối với chương trình chất lượng và an toàn bệnh nhân của bệnh\nviện.\n\nCác hoạt động đo lường tạo cơ hội để đánh giá các dịch vụ. Các nhà lãnh đạo khoa/dịch vụ tham gia vào\nviệc bổ nhiệm, phân định đặc quyền, đánh giá hoạt động chuyên môn đang diễn ra và tái bổ nhiệm các\nbác sĩ trong khoa hoặc dịch vụ.\n\nMột số khoa, chẳng hạn như phòng ngừa và kiểm soát nhiễm trùng, quản lý cơ sở, X quang và phòng xét\nnghiệm lâm sàng, có các chương trình giám sát hoặc kiểm soát chất lượng đang diễn ra được đưa vào các\nưu tiên đo lường và được mô tả trong các tiêu chuẩn liên quan đến các dịch vụ đó.\n\nCác yếu tố đo lường được của GLD.06.01\n1.\nCác nhà lãnh đạo khoa/dịch vụ triển khai các biện pháp chất lượng trên toàn bệnh viện liên\nquan đến các dịch vụ do khoa hoặc dịch vụ của họ cung cấp, bao gồm bất kỳ dịch vụ theo hợp\nđồng nào mà họ chịu trách nhiệm. (Xem thêm FMS.02.00, ME 2)\n2.\nCác nhà lãnh đạo khoa/dịch vụ triển khai các biện pháp chất lượng để giảm sự thay đổi và cải\nthiện các quy trình trong khoa hoặc dịch vụ. (Xem thêm FMS.02.00, ME 3)\n3.\nCác nhà lãnh đạo khoa/dịch vụ lựa chọn các biện pháp dựa trên nhu cầu cải tiến và khi cải tiến\nđã được duy trì, hãy lựa chọn một biện pháp mới. (Xem thêm QPS.04.00, ME 2)\n4.\nKhi áp dụng, đánh giá sự tham gia vào các hoạt động chất lượng và kết quả của các hoạt động\nđo lường được đưa vào đánh giá nhân viên của khoa.","m":[],"sec":"Chỉ đạo các khoa và dịch vụ của bệnh viện"},{"c":"GLD.06.02","ch":"GLD","t":"Các nhà lãnh đạo khoa/dịch vụ lựa chọn và triển khai các hướng dẫn thực hành lâm sàng, lộ trình lâm sàng và giao thức lâm sàng khi thiết kế hoặc cải thiện các quy trình.","p":"Hướng dẫn thực hành lâm sàng, lộ trình lâm sàng và giao thức lâm sàng là những tuyên bố bao gồm các khuyến\nnghị nhằm tối ưu hóa việc chăm sóc bệnh nhân được đưa ra dựa trên đánh giá có hệ thống về bằng chứng và\nđánh giá lợi ích và tác hại của các lựa chọn chăm sóc thay thế.\n\nHướng dẫn lâm sàng được ban hành bởi các nguồn khoa học (ví dụ: các hiệp hội và hội y khoa) hoặc các cơ quan\nchính phủ (các nguồn bên ngoài). Lộ trình và giao thức có thể được sử dụng thay thế cho nhau và được sử dụng\nđể triển khai và hợp lý hóa các yêu cầu của \"lộ trình lâm sàng\".\n\nMục tiêu của bệnh viện bao gồm:\n• Chuẩn hóa quy trình chăm sóc lâm sàng\n• Giảm thiểu rủi ro trong quy trình chăm sóc, đặc biệt là những rủi ro liên quan đến các bước ra quyết định quan\ntrọng\n\nGovernance, Leadership,\n\n• Cung cấp dịch vụ chăm sóc lâm sàng kịp thời, hiệu quả bằng cách sử dụng hiệu quả các nguồn lực sẵn có\n• Luôn cung cấp dịch vụ chăm sóc chất lượng cao bằng các phương pháp dựa trên bằng chứng\n\nCác bệnh viện sử dụng nhiều công cụ khác nhau để đạt được những mục tiêu này và các mục tiêu khác. Ví dụ, các bác sĩ\nchăm sóc sức khỏe tìm cách phát triển các quy trình chăm sóc lâm sàng và đưa ra quyết định chăm sóc lâm sàng dựa trên\nbằng chứng khoa học tốt nhất hiện có. Các hướng dẫn thực hành lâm sàng, lộ trình lâm sàng và giao thức lâm sàng là\nnhững công cụ hữu ích trong nỗ lực này để hiểu và áp dụng khoa học tốt nhất vào một chẩn đoán hoặc tình trạng cụ thể.\nBệnh viện chỉ sử dụng các hướng dẫn thực hành lâm sàng, lộ trình lâm sàng và giao thức lâm sàng đã được các nguồn có\nthẩm quyền có liên quan xem xét và xác nhận; ví dụ, một hiệp hội hoặc hội đồng chuyên môn quốc gia hoặc một tổ chức\nquốc tế công bố các hướng dẫn đã được phê duyệt. Nếu các hướng dẫn thực hành lâm sàng, lộ trình lâm sàng và giao\nthức lâm sàng được bệnh viện xây dựng, chúng sẽ được gửi đến một nguồn có thẩm quyền (ví dụ, Bộ Y tế hoặc các tổ\nchức chuyên môn) để xác nhận.\n\nThông thường, việc triển khai hiệu quả các hướng dẫn thực hành lâm sàng, lộ trình lâm sàng và giao thức lâm sàng sẽ\nyêu cầu các lộ trình lâm sàng và giao thức lâm sàng phải được điều chỉnh hoặc phát triển. Các lộ trình và giao thức là\nnhững công cụ hữu ích trong nỗ lực này nhằm đảm bảo trình tự, tích hợp và phối hợp hiệu quả việc chăm sóc và sử dụng\nhiệu quả các nguồn lực sẵn có.\n\nCác hướng dẫn thực hành lâm sàng, lộ trình lâm sàng và giao thức lâm sàng có liên quan đến nhóm bệnh nhân và sứ mệnh\ncủa bệnh viện đáp ứng các tiêu chí sau:\n•\nĐược lựa chọn trong số những hướng dẫn áp dụng cho các dịch vụ và bệnh nhân của bệnh viện (các hướng\ndẫn quốc gia bắt buộc được đưa vào quy trình này, nếu có).\n•\nĐược đánh giá về mức độ liên quan của chúng đối với các nhóm bệnh nhân đã xác định.\n•\nĐược điều chỉnh khi cần thiết cho công nghệ, thuốc và các nguồn lực khác của bệnh viện hoặc cho các\n•\nchuẩn mực chuyên môn quốc gia được chấp nhận.\n•\nĐược đánh giá về bằng chứng khoa học và sự chứng thực của chúng bởi một nguồn có thẩm quyền.\n•\nĐược bệnh viện chính thức chấp thuận hoặc áp dụng.\n•\nĐược triển khai và đo lường để sử dụng và hiệu quả nhất quán.\n•\nĐược hỗ trợ bởi đội ngũ nhân viên được đào tạo để áp dụng các hướng dẫn hoặc lộ trình.\n•\nĐược cập nhật định kỳ dựa trên những thay đổi trong bằng chứng và đánh giá các quy trình và kết quả.\nVì nhiều hướng dẫn, giao thức và lộ trình liên quan tác động đến nhiều khoa hoặc dịch vụ lâm sàng, nên các nhà lãnh đạo\nđược kỳ vọng sẽ cùng nhau xác định ít nhất năm lĩnh vực ưu tiên để tập trung vào—những hướng dẫn nào sẽ tác động\nđến chất lượng và sự an toàn của việc chăm sóc bệnh nhân và giảm thiểu sự thay đổi không mong muốn trong kết quả.\nQuy trình lựa chọn tập thể này không cấm một khoa hoặc dịch vụ riêng lẻ lựa chọn các hướng dẫn bổ sung, cũng như\nbất kỳ giao thức hoặc lộ trình liên quan nào, cụ thể hơn cho các dịch vụ được cung cấp trong khoa hoặc dịch vụ đó.\n\nCác yếu tố đo lường được của GLD.06.02\n1.\nHàng năm, các nhà lãnh đạo khoa/dịch vụ cùng nhau xác định ít nhất năm lĩnh vực ưu tiên để tập\ntrung sử dụng các hướng dẫn thực hành lâm sàng.\n2.\nCác nhà lãnh đạo khoa/dịch vụ cộng tác với các nhân viên lâm sàng phù hợp để lựa chọn, xem xét,\nphê duyệt và sửa đổi các hướng dẫn thực hành lâm sàng, lộ trình lâm sàng và giao thức lâm sàng khi\ncần thiết.\n3.\nCác nhà lãnh đạo khoa/dịch vụ triển khai các hướng dẫn thực hành lâm sàng, lộ trình lâm sàng và\ngiao thức lâm sàng cho từng lĩnh vực ưu tiên được xác định có liên quan đến khoa/dịch vụ.\n4.\nCác nhà lãnh đạo khoa/dịch vụ chứng minh cách triển khai các hướng dẫn thực hành lâm sàng, lộ\ntrình lâm sàng và giao thức lâm sàng hỗ trợ việc giảm sự thay đổi trong quy trình và cải thiện kết\nquả.\n\nGovernance, Leadership,\ngovernanCe, leaderShIP, and dIreCtIon\n\nĐạo đức tổ chức và lâm sàng","m":[],"sec":"Quản trị, Lãnh đạo"},{"c":"GLD.07.00","ch":"GLD","t":"Các nhà lãnh đạo bệnh viện thiết lập một khuôn khổ quản lý đạo đức thúc đẩy văn hóa thực hành đạo đức và ra quyết định để đảm bảo rằng việc chăm sóc bệnh nhân được cung cấp trong các chuẩn mực kinh doanh, tài chính, đạo đức và pháp lý và bảo vệ bệnh nhân cũng như quyền của họ.","p":"Bệnh viện phải đối mặt với nhiều thách thức trong việc cung cấp dịch vụ chăm sóc sức khỏe an toàn, chất lượng cao.\nVới những tiến bộ trong công nghệ y tế, hạn chế về tài chính và kỳ vọng ngày càng tăng, những tình huống khó xử và\ntranh cãi về đạo đức trở nên phổ biến hơn nhiều. Các nhà lãnh đạo bệnh viện có trách nhiệm chuyên môn và pháp lý\ntrong việc tạo ra và thúc đẩy một môi trường và văn hóa hoạt động trong khuôn khổ đạo đức.\n\nKhuôn khổ đạo đức phải áp dụng cho cả hoạt động kinh doanh và lâm sàng của bệnh viện. Các nhà lãnh đạo bệnh viện\nphải thể hiện hành vi đạo đức và xây dựng các hướng dẫn về hiệu suất và hành vi của tổ chức. Các hành động của các\nnhà lãnh đạo bệnh viện và các hướng dẫn của bệnh viện về hành vi đạo đức phải phù hợp với các chính sách của tổ\nchức và tầm nhìn, sứ mệnh và tuyên bố giá trị của bệnh viện.\n\nKhuôn khổ hỗ trợ các bác sĩ chăm sóc sức khỏe, các nhân viên khác, bệnh nhân và gia đình của bệnh viện khi đối mặt\nvới các tình huống khó xử về đạo đức trong việc chăm sóc bệnh nhân, chẳng hạn như bất đồng giữa các chuyên gia,\nbất đồng giữa bệnh nhân và bác sĩ chăm sóc sức khỏe của họ và bất đồng giữa các thành viên trong gia đình về người\nthân của họ không có khả năng ra quyết định. Hỗ trợ luôn sẵn có và bao gồm các nguồn lực về đạo đức và đào tạo cho\ntất cả nhân viên. Ngoài ra, các chuẩn mực quốc gia và quốc tế liên quan đến quyền con người và đạo đức nghề nghiệp\nphải được xem xét khi tạo khuôn khổ đạo đức và các tài liệu hướng dẫn.\n\nBệnh viện hoạt động trong khuôn khổ này để thực hiện các mục tiêu sau:\n•\nTiết lộ quyền sở hữu và mọi xung đột lợi ích (ví dụ: mối quan hệ giữa bác sĩ giới thiệu và các nguồn dịch vụ chẩn\nđoán hình ảnh hoặc xét nghiệm bên ngoài).\n•\nMô tả trung thực các dịch vụ của mình cho bệnh nhân.\n•\nBảo vệ tính bảo mật của thông tin bệnh nhân.\n•\nCung cấp các chính sách nhập viện, chuyển viện và xuất viện rõ ràng.\n•\nLập hóa đơn chính xác cho các dịch vụ của mình và đảm bảo rằng các ưu đãi tài chính và thỏa thuận thanh toán\nkhông làm ảnh hưởng đến việc chăm sóc bệnh nhân.\n•\nThiết lập cơ chế mà các bác sĩ chăm sóc sức khỏe và các nhân viên khác có thể báo cáo các lỗi lâm sàng và nêu lên\ncác mối quan ngại về đạo đức mà không bị trừng phạt, bao gồm cả hành vi gây rối của nhân viên liên quan đến\ncác vấn đề lâm sàng và/hoặc hoạt động.\n•\nHỗ trợ một môi trường cho phép thảo luận tự do về các mối quan ngại về đạo đức mà không sợ bị trả thù.\n•\nCung cấp giải pháp hiệu quả cho các xung đột về đạo đức trong một khung thời gian được xác định rõ ràng.\n•\nĐảm bảo không phân biệt đối xử trong các hoạt động tuyển dụng và cung cấp dịch vụ chăm sóc bệnh nhân trong\nbối cảnh các chuẩn mực văn hóa và quy định của quốc gia.\n•\nGiảm sự chênh lệch trong việc tiếp cận dịch vụ chăm sóc sức khỏe và kết quả lâm sàng bằng cách xác định các\nnhóm dân số dễ bị tổn thương.\n\nGovernance, Leadership,\n\nCác yếu tố đo lường được của GLD.07.00\n1.\nLãnh đạo bệnh viện thiết lập khuôn khổ cho hoạt động quản lý đạo đức của bệnh viện, thúc đẩy những\nđiều sau:\n•\nVăn hóa thực hành đạo đức và ra quyết định để đảm bảo bảo vệ bệnh nhân và quyền của họ (Xem thêm\nCOP.10.02, ME 2; HRP.01.02, ME 1; HRP.01.03, ME 3)\n•\nCơ chế mà các bác sĩ và nhân viên khác có thể nêu lên những lo ngại về đạo đức mà không sợ bị trả thù\n(Xem thêm GLD.07.01, ME 5)\n•\nCấu trúc và quy trình hỗ trợ giám sát các vấn đề đạo đức nghề nghiệp và kinh doanh.\n2.\nKhuôn khổ đạo đức đảm bảo rằng việc chăm sóc bệnh nhân được cung cấp trong khuôn khổ kinh doanh,\ntài chính, đạo đức và pháp lý.\n3.\nBệnh viện đảm bảo không phân biệt đối xử trong các hoạt động tuyển dụng và cung cấp dịch vụ chăm sóc\nbệnh nhân trong bối cảnh các chuẩn mực văn hóa và quy định của quốc gia.\n4.\nLãnh đạo bệnh viện xác định các chuẩn mực đạo đức quốc gia và quốc tế áp dụng khi xây dựng khuôn khổ\nứng xử đạo đức của bệnh viện.\n5.\nBệnh viện lập hóa đơn chính xác cho các dịch vụ và đảm bảo rằng các ưu đãi tài chính và thỏa thuận thanh\ntoán không ảnh hưởng đến việc chăm sóc, điều trị hoặc dịch vụ của bệnh nhân.\n6.\nBệnh viện đưa ra giải pháp hiệu quả cho các xung đột về đạo đức phát sinh trong một khung thời gian xác\nđịnh.","m":[],"sec":"Đạo đức tổ chức và lâm sàng"},{"c":"GLD.07.01","ch":"GLD","t":"Lãnh đạo bệnh viện tạo ra và duy trì văn hóa an toàn và chất lượng trong toàn bệnh viện.","p":"An toàn và chất lượng phát triển mạnh mẽ trong một môi trường hỗ trợ tinh thần đồng đội và tôn trọng người\nkhác, bất kể vị trí của họ trong bệnh viện. Các nhà lãnh đạo bệnh viện thể hiện cam kết của họ đối với văn hóa an\ntoàn và các nhà lãnh đạo đặt ra kỳ vọng cho những người làm việc trong bệnh viện.\n\nVăn hóa an toàn được định nghĩa là \"một môi trường hợp tác trong đó các bác sĩ lâm sàng đối xử với nhau một\ncách tôn trọng, các nhà lãnh đạo thúc đẩy tinh thần đồng đội hiệu quả và thúc đẩy sự an toàn về mặt tâm lý, các\nnhóm học hỏi từ những sai lầm và những lần suýt xảy ra tai nạn (hoặc những tình huống nguy cấp), những\nngười chăm sóc nhận thức được những hạn chế cố hữu của hiệu suất làm việc của con người trong các hệ thống\nphức tạp (nhận biết căng thẳng) và có một quá trình học hỏi và thúc đẩy cải tiến rõ ràng thông qua các cuộc họp\nrút kinh nghiệm\".\nCác nhà lãnh đạo bệnh viện khuyến khích tinh thần đồng đội và tạo ra các cấu trúc, quy trình và chương trình cho\nphép văn hóa tích cực này phát triển mạnh mẽ. Hành vi đe dọa người khác và ảnh hưởng đến tinh thần hoặc sự\nluân chuyển nhân viên làm suy yếu văn hóa an toàn và có thể gây hại cho việc chăm sóc bệnh nhân. Các nhà lãnh\nđạo phải giải quyết hành vi như vậy ở những cá nhân làm việc ở mọi cấp độ của bệnh viện, bao gồm cả nhân viên\nquản lý, y tế, lâm sàng và hành chính, và các thành viên của cơ quan quản lý. Các đặc điểm chính của chương trình\nvăn hóa an toàn bao gồm:\n•\nThừa nhận bản chất rủi ro cao của các hoạt động của bệnh viện và quyết tâm đạt được các hoạt\nđộng an toàn liên tục\n•\nMột môi trường mà các cá nhân có thể báo cáo lỗi hoặc suýt xảy ra tai nạn mà không sợ bị khiển\ntrách hoặc trừng phạt\n•\nKhuyến khích sự hợp tác giữa các cấp bậc và chuyên ngành để tìm ra giải pháp cho các vấn đề về an\ntoàn bệnh nhân\n•\nCam kết của tổ chức về các nguồn lực, chẳng hạn như thời gian của nhân viên, giáo dục, phương\npháp an toàn để báo cáo các vấn đề, v.v., để giải quyết các mối quan ngại về an toàn.\n\nChăm sóc sức khỏe vẫn tiếp tục có văn hóa đổ lỗi cho cá nhân, điều này làm suy yếu sự tiến bộ của văn hóa an\ntoàn. Có những trường hợp cá nhân không nên bị đổ lỗi cho một lỗi; ví dụ, khi có sự giao tiếp kém giữa bệnh\nnhân và nhân viên, khi cần phải đưa ra quyết định nhanh chóng hoặc khi có những sai sót về thiết kế yếu tố con\nngười trong quá trình điều trị. Tuy nhiên, một số lỗi nhất định là kết quả của hành vi không an toàn và cần phải\nchịu trách nhiệm.\n\nGovernance, Leadership,\ngovernanCe, leaderShIP, and dIreCtIon\nVí dụ về hành vi không an toàn bao gồm không tuân thủ hướng dẫn vệ sinh tay, không thực hiện thời gian\nchờ trước khi phẫu thuật hoặc không đánh dấu vị trí phẫu thuật.\n\nVăn hóa an toàn ngày càng hoàn thiện được phản ánh qua số lượng bệnh nhân và gia đình ngày càng hài\nlòng với dịch vụ chăm sóc của bạn và giảm hoặc không có các trường hợp suýt xảy ra tai nạn và tất cả các\nbiến cố bất lợi, bao gồm cả các biến cố cảnh báo.\n\nVăn hóa an toàn bao gồm việc xác định và giải quyết các vấn đề liên quan đến hệ thống dẫn đến hành vi\nkhông an toàn. Tuy nhiên, đồng thời, các bệnh viện phải duy trì trách nhiệm giải trình bằng cách thiết lập\nchính sách không khoan nhượng đối với hành vi không an toàn. Trách nhiệm giải trình phân biệt giữa lỗi\ncủa con người (chẳng hạn như nhầm lẫn), hành vi có nguy cơ (ví dụ: đi tắt) và hành vi không an toàn\n(chẳng hạn như bỏ qua các bước an toàn bắt buộc). Việc thiết lập và hỗ trợ văn hóa an toàn của tổ chức có\nthể bao gồm các cuộc bổ nhiệm ủy ban liên quan đến các khoa khác nhau của bệnh viện (ví dụ: khoa dược,\nphòng xét nghiệm, khoa kỹ thuật, khoa điều dưỡng). Ủy ban được bổ nhiệm trình bày các bản cập nhật\nđịnh kỳ cho cơ quan quản lý để xác định các vấn đề ảnh hưởng đến chất lượng chung và an toàn của bệnh\nnhân. Các nhà lãnh đạo bệnh viện đánh giá văn hóa này thường xuyên bằng nhiều phương pháp khác\nnhau, chẳng hạn như khảo sát chính thức, nhóm tập trung, phỏng vấn nhân viên và phân tích dữ liệu.\nLãnh đạo bệnh viện khuyến khích làm việc nhóm và tạo ra các cấu trúc, quy trình và chương trình cho\nphép văn hóa tích cực này phát triển mạnh mẽ. Lãnh đạo bệnh viện phải giải quyết các hành vi không\nmong muốn của các cá nhân làm việc ở mọi cấp độ của bệnh viện, bao gồm quản lý, nhân viên lâm sàng và\nphi lâm sàng, bác sĩ chăm sóc sức khỏe độc lập và các thành viên của đơn vị quản lý.\n\nCác yếu tố đo lường được của GLD.07.01\n1.\nLãnh đạo bệnh viện thiết lập và hỗ trợ văn hóa tổ chức khuyến khích báo cáo và thảo luận về các cơ hội\ncải thiện văn hóa an toàn trong tổ chức. (Xem thêm Chính sách sự kiện Sentinel và APR.09.00, ME 1)\n2.\nLãnh đạo bệnh viện xây dựng bộ quy tắc ứng xử để xác định và sửa chữa các hành vi không thể chấp\nnhận được.\n3.\nLãnh đạo bệnh viện thiết lập chương trình giáo dục theo lịch trình thường xuyên và cung cấp các nguồn\nlực (như tài liệu và khuyến cáo) liên quan đến văn hóa an toàn của bệnh viện cho tất cả các cá nhân làm\nviệc tại bệnh viện. (Xem thêm SQE.01.07, ME 3; SQE.07.00, ME 2)\n4.\nLãnh đạo bệnh viện cung cấp hệ thống dễ tiếp cận và bảo mật để báo cáo các vấn đề liên quan đến văn\nhóa an toàn trong bệnh viện.\n5.\nLãnh đạo bệnh viện triển khai quy trình để ngăn chặn việc trả thù đối với những cá nhân báo cáo các\nvấn đề về văn hóa an toàn và đảm bảo rằng tất cả các báo cáo đều được điều tra trong một khung thời\ngian xác định. (Xem thêm GLD.07.00, ME 1)\n6.\nCác nhà lãnh đạo bệnh viện xác định và hành động về các vấn đề hệ thống khiến các bác sĩ tham\ngia vào các hành vi không an toàn.","m":[],"sec":"Đạo đức tổ chức và lâm sàng"},{"c":"GLD.07.02","ch":"GLD","t":"Bệnh viện triển khai chương trình phòng chống bạo lực tại nơi làm việc để cung cấp một nơi làm việc an toàn và bảo mật.","p":"Chương trình phòng ngừa bạo lực tại nơi làm việc thiết lập khuôn khổ cho các bệnh viện để thực hiện và quản lý\nhiệu quả các hệ thống phòng ngừa bạo lực tại nơi làm việc, bao gồm giám sát lãnh đạo, chính sách và quy trình, hệ\nthống báo cáo, thu thập và phân tích dữ liệu và các chiến lược sau sự cố.\n\nTỷ lệ bạo lực đối với nhân viên chăm sóc sức khỏe đã đạt đến mức độ khủng khiếp. Hơn nữa, với chỉ trung bình\n20% đến 60% các sự cố được báo cáo, phạm vi đầy đủ của vấn đề vẫn chưa được nhận ra. Bạo lực tại nơi làm việc\nđược định nghĩa là \"hành vi hoặc mối đe dọa xảy ra tại nơi làm việc có thể bao gồm bất kỳ hành vi nào sau đây: xâm\nlược bằng lời nói, không bằng lời nói, bằng văn bản hoặc hành động; lời nói hoặc hành động đe dọa, đe dọa, quấy\nrối hoặc làm nhục; bắt nạt; phá hoại; quấy rối tình dục; tấn công thể xác; hoặc các hành vi đáng lo ngại khác liên\nquan đến tất cả nhân viên, bệnh nhân hoặc khách thăm\".\n\nGovernance, Leadership,\nBạo lực tại nơi làm việc đã trở thành một vấn đề ngày càng phổ biến trong các tổ chức chăm sóc sức khỏe.\nTình trạng thiếu hụt nhân viên, tình trạng bệnh nhân cấp tính tăng lên và quan niệm sai lầm rằng bạo lực\nkhông xảy ra trong các tổ chức chăm sóc sức khỏe—hoặc nếu bạo lực xảy ra, thì đó là một phần của công\nviệc—chỉ là một số rào cản đối với việc thừa nhận rằng bạo lực tại nơi làm việc tồn tại và phát triển các\nchương trình phòng ngừa bạo lực.\n\nChỉ định một người lãnh đạo chịu trách nhiệm cho chương trình phòng ngừa bạo lực tại nơi làm việc của\nbệnh viện sẽ thiết lập các ranh giới trách nhiệm rõ ràng. Ngoài ra, việc thiết lập các chính sách và quy trình\nchuẩn hóa để ngăn ngừa, ứng phó, báo cáo và theo dõi các sự kiện hoặc sự cố suýt xảy ra sẽ làm giảm sự khác\nbiệt trong chương trình. Việc thu thập dữ liệu và các cấu trúc báo cáo đơn giản, dễ tiếp cận cho thấy cam kết\ncung cấp một môi trường làm việc an toàn và bảo mật. Việc báo cáo thường xuyên các sự cố và xu hướng cho\ncơ quan quản lý sẽ thúc đẩy tính minh bạch và thiết lập thêm trách nhiệm giải trình cho chương trình. Các ví\ndụ về kết quả đo lường thành công của chương trình bao gồm:\n•\nGiảm tỷ lệ gây hại do hành vi bạo lực\n•\nKết quả Khảo sát mức độ gắn kết của nhân viên và báo cáo của nhân viên trên toàn tổ chức cho thấy\nnhân viên cảm thấy \"rất\n•\nan toàn\".\n•\nBệnh nhân và gia đình báo cáo rằng họ cảm thấy an toàn trong môi trường chăm sóc sức khỏe.\n•\nNhân viên cảm thấy thoải mái khi báo cáo các sự cố và liên quan đến những người có thẩm quyền.\n\nCác yếu tố đo lường được của GLD.07.02\n1.\nChương trình phòng ngừa bạo lực tại nơi làm việc do một cá nhân được chỉ định lãnh đạo và được\nmột nhóm liên ngành phát triển.\n2.\nD Bệnh viện xây dựng và thực hiện các chính sách và quy trình bằng văn bản để ngăn ngừa và ứng phó\nvới bạo lực tại nơi làm việc. (Xem thêm FMS.03.00, ME 1; FMS.04.00, ME 7; SQE.02.02, ME 1 và 3)\n3.\nBệnh viện thực hiện quy trình báo cáo sự cố để phân tích sự cố và xu hướng. (Xem thêm FMS.03.00,\nME 3 và 5; FMS.04.00, ME 9)\n4.\nBệnh viện thực hiện quy trình theo dõi và hỗ trợ nạn nhân và nhân chứng bị ảnh hưởng bởi bạo lực\ntại nơi làm việc, bao gồm tư vấn tâm lý và chấn thương, nếu cần.\n5.\nBệnh viện thực hiện quy trình báo cáo các vụ việc bạo lực tại nơi làm việc cho cơ quan quản lý. (Xem\nthêm SQE.02.02, ME 3)\n\nGiáo dục chuyên môn y tế\n\nLưu ý: Đối với các bệnh viện đáp ứng các tiêu chí đủ điều kiện để được công nhận là bệnh viện trung tâm y\ntế học thuật, GLD.08.00 áp dụng cho giáo dục dành cho sinh viên điều dưỡng và/hoặc các sinh viên chuyên\nngành y tế không phải y khoa khác. Đối với các bệnh viện không phải là trung tâm y tế học thuật,\nGLD.08.00 áp dụng cho giáo dục dành cho sinh viên và thực tập sinh y khoa, sinh viên điều dưỡng và/hoặc\ncác sinh viên chuyên ngành y tế khác.","m":[],"sec":"Đạo đức tổ chức và lâm sàng"},{"c":"GLD.08.00","ch":"GLD","t":"Giáo dục chuyên môn y tế, khi được cung cấp trong bệnh viện, được hướng dẫn bởi các thông số giáo dục do chương trình học thuật tài trợ và các nhà lãnh đạo bệnh viện xác định.","p":"Thông thường, các bệnh viện kết hợp vai trò giảng dạy vào sứ mệnh của mình và là bối cảnh lâm sàng cho một\nphần của chương trình đào tạo y khoa, điều dưỡng, các bác sĩ chăm sóc sức khỏe khác và các chương trình đào tạo\nsinh viên khác. Ví dụ, sinh viên và thực tập sinh y khoa có thể dành một vài tháng để tích lũy kinh nghiệm lâm sàng\ntại một bệnh viện giảng dạy cộng đồng hoặc một chương trình điều dưỡng có thể được tổ chức tại bệnh viện.\nCác bệnh viện này đóng vai trò quan trọng; tuy nhiên, chúng không được coi là trung tâm y khoa học thuật cho mục\nđích của các tiêu chuẩn này.\n\nLãnh đạo bệnh viện liên lạc với cơ sở đào tạo để giám sát chặt chẽ khi bệnh viện tham gia bất kỳ loại chương trình\nđào tạo nào. Là một phần của sự phối hợp này, bệnh viện thực hiện các hoạt động sau:\n\nGovernance, Leadership,\ngovernanCe, leaderShIP, and dIreCtIon\n•\nThu thập và chấp nhận các thông số của chương trình học thuật tài trợ.\n•\nThu thập hồ sơ đầy đủ của tất cả sinh viên và học viên trong bệnh viện.\n•\nHiểu và cung cấp mức độ giám sát cho tất cả học viên.\n•\nTích hợp sinh viên và học viên vào chương trình định hướng, chất lượng và an toàn bệnh nhân, phòng ngừa và\nkiểm soát nhiễm trùng và các chương trình khác của bệnh viện.\n\nCác yếu tố đo lường được của GLD.08.00\n1.\nBệnh viện cung cấp cơ chế giám sát chương trình đào tạo.\n2.\nBệnh viện có hồ sơ đầy đủ về tất cả sinh viên và học viên trong bệnh viện.\n3.\nBệnh viện có tài liệu về tình trạng ghi danh, giấy phép hoặc chứng chỉ đạt được và phân loại học vấn của sinh viên và\nhọc viên.\n4.\nBệnh viện cung cấp mức độ giám sát cần thiết cho từng loại và trình độ của sinh viên và học viên.\n5. Bệnh viện cung cấp cơ hội cho sinh viên và học viên đánh giá chương trình giáo dục và nhận phản hồi.\n\nLưu ý: Các trung tâm y tế học thuật phải đáp ứng các yêu cầu này ngoài chương “Chương trình nghiên cứu đối tượng là con\nngười” (HRP).","m":[],"sec":"Giáo dục chuyên môn y tế"}];})(window);
